window.RECIPES = [{"id": 0, "title": "HARISSA FISH FILLET WITH BULGUR SALAD AND AJVAR DIP", "subtitle": "at least -20% calories compared to the other recipes", "title_de": "HARISSA-FISCHFILET MIT BULGURSALAT UND AJVAR-DIP", "prep_time_min": 40, "difficulty": 2, "protein_type": "fish", "ingredients": [{"name_de": "Bulgur", "name": "bulgur", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "Gemüsebrühe", "name": "vegetable stock", "quantity": "300", "unit": "ml", "category": "pantry"}, {"name_de": "Tomate", "name": "tomato", "quantity": "2", "unit": "Stück", "category": "produce"}, {"name_de": "Frühlingszwiebel", "name": "spring onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Zitrone, gewachst", "name": "lemon", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Gewürzmischung \"Hello Harissa\"", "name": "Hello Harissa spice mix", "quantity": "1", "unit": "EL", "category": "pantry"}, {"name_de": "Seehecht", "name": "hake", "quantity": "1", "unit": "Stück", "category": "meat & fish"}, {"name_de": "Ajvar", "name": "ajvar (red pepper spread)", "quantity": "46", "unit": "g", "category": "pantry"}, {"name_de": "Joghurt", "name": "yogurt", "quantity": "17", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Mayonnaise", "name": "mayonnaise", "quantity": "5", "unit": "ml", "category": "pantry"}, {"name_de": "Tomatenpesto", "name": "tomato pesto", "quantity": "1", "unit": "EL", "category": "pantry"}, {"name_de": "Olivenöl", "name": "olive oil", "quantity": "2", "unit": "EL", "category": "pantry"}], "steps": ["Cook the bulgur: Fill a small pot with 350 ml [525 ml | 700 ml] boiling water. Add the vegetable stock, season lightly with salt, stir in the bulgur, bring to the boil once, place the lid on, turn off the heat, and let the bulgur swell for approx. 25 min until all the water has been absorbed.", "Make the ajvar dip: In a small bowl, stir together the ajvar, yogurt, and mayonnaise, and season to taste with a pinch of salt and pepper.", "Cut the lemon into 4 wedges. Halve the tomatoes, remove the core, and cut the tomato halves into 0.5 cm cubes. Place in a large bowl with a pinch of salt and the juice of 1 [1.5 | 2] lemon wedge(s). Set aside to marinate.", "Pat the fish fillets dry and rub both sides with the 'Hello Harissa' spice blend, salt, and pepper. Heat 1 tbsp oil in a large pan over medium-high heat and fry the fish fillets for 3-4 min per side until cooked through. Remove from the pan.", "Fluff the bulgur lightly with a fork, add to the bowl with the marinated tomatoes, and fold in the spring onion greens. Season to taste with salt, pepper, and the juice of the remaining lemon wedges.", "Divide the bulgur salad onto plates, place the pan-fried fish fillets on top, and garnish with green spring onion rings and paprika. Serve with the ajvar dip on the side."], "source": "hello_fresh_1.pdf"}, {"id": 1, "title": "FUSION NICOISE WITH TUNA AND SRIRACHA SESAME MAYO", "subtitle": "with butter beans and marinated onion", "title_de": "FUSION NIÇOISE MIT THUNFISCH UND SRIRACHA-SESAM-MAYO", "prep_time_min": 30, "difficulty": 1, "protein_type": "fish", "ingredients": [{"name_de": "Ofenkartoffel", "name": "baking potato", "quantity": "320", "unit": "g", "category": "produce"}, {"name_de": "Buschbohnen", "name": "green beans", "quantity": "100", "unit": "g", "category": "pantry"}, {"name_de": "Butterbohnen", "name": "butter beans", "quantity": "160", "unit": "g", "category": "pantry"}, {"name_de": "Salatherz (Romana)", "name": "romaine lettuce heart", "quantity": "50", "unit": "g", "category": "produce"}, {"name_de": "Vegane Mayonnaise mit schwarzem Sesam", "name": "vegan mayonnaise with black sesame", "quantity": "100", "unit": "g", "category": "pantry"}, {"name_de": "Skipjack Thunfisch im eigenen Saft", "name": "skipjack tuna in its own juice", "quantity": "1", "unit": "Stück", "category": "meat & fish"}, {"name_de": "Sriracha Sauce", "name": "sriracha sauce", "quantity": "5", "unit": "ml", "category": "pantry"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "0,5", "unit": "Stück", "category": "produce"}, {"name_de": "Olivenöl", "name": "olive oil", "quantity": "3", "unit": "EL", "category": "pantry"}, {"name_de": "Essig", "name": "vinegar", "quantity": "1,5", "unit": "EL", "category": "pantry"}, {"name_de": "Honig", "name": "honey", "quantity": "0,5", "unit": "TL", "category": "pantry"}, {"name_de": "Salz", "name": "salt", "quantity": "1", "unit": "TL", "category": "pantry"}], "steps": ["Prep work: Trim the ends of the green beans and halve them crosswise. Peel the potatoes and cut into 1 cm thick slices. Halve the cherry tomatoes.", "Cook the vegetables: Fill a large pot with approx. 2 l hot water, add 1 tsp [1.5 tsp | 2 tsp] salt, and bring to the boil. Add the potatoes and cook for 15-18 min. Add the beans 5 min before the end of cooking time. Drain everything through a sieve.", "Halve the onion and cut into thin strips. In a large bowl, mix together a little vinegar, sugar, salt, and the onion strips and set aside to marinate.", "For the tuna: Drain the tuna using the lid of the can. In a small bowl, mix together the sriracha and sesame oil. Add the drained tuna and stir to combine.", "Add the lettuce to the large bowl, then the beans, and drizzle with 3 tbsp [4.5 tbsp | 6 tbsp] olive oil and honey to taste. Season with salt and pepper and toss to combine.", "Plate up: Divide the salad into deep bowls and serve with the sriracha sesame mayo."], "source": "hello_fresh_1.pdf"}, {"id": 2, "title": "SPICY FIERY GRILLED CHEESE TACOS", "subtitle": "with caramelized onions and aioli", "title_de": "WÜRZIG-FEURIGE GRILLKÄSE-TACOS", "prep_time_min": 35, "difficulty": 1, "protein_type": "vegetarian", "ingredients": [{"name_de": "Weizentortillas", "name": "wheat tortillas", "quantity": "3", "unit": "Stück", "category": "pantry"}, {"name_de": "Grillkäse", "name": "grilling cheese", "quantity": "200", "unit": "g", "category": "dairy & eggs"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Chilischote", "name": "red chili", "quantity": "0,5", "unit": "Stück", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Gurke", "name": "cucumber", "quantity": "75", "unit": "g", "category": "produce"}, {"name_de": "Rucola", "name": "arugula", "quantity": "25", "unit": "g", "category": "produce"}, {"name_de": "Mayonnaise", "name": "mayonnaise", "quantity": "50", "unit": "g", "category": "pantry"}, {"name_de": "Zitrone, gewachst", "name": "lemon", "quantity": "0,5", "unit": "Stück", "category": "produce"}, {"name_de": "Oregano, gerebelt", "name": "dried oregano", "quantity": "0,5", "unit": "TL", "category": "pantry"}, {"name_de": "Balsamicoessig", "name": "balsamic vinegar", "quantity": "1", "unit": "EL", "category": "pantry"}, {"name_de": "Zucker", "name": "sugar", "quantity": "1", "unit": "Prise", "category": "pantry"}], "steps": ["Dice the cucumber: Trim the ends of the cucumber and cut into 1 cm cubes. Cut the lemon into 6 wedges. Place the cucumber in a bowl with the juice of 1-2 lemon wedges and a pinch of salt. Set aside to marinate.", "Slice the onion: Halve the onion and cut into thin strips, then roughly chop. Add a pinch of salt.", "Caramelize the onions: Heat 1 tbsp [1.5 tbsp | 2 tbsp] oil in a small pan over medium heat. Add the onions and cook, stirring occasionally, for 8-10 min until soft and caramelized. Season with salt and pepper.", "Marinate the grilling cheese: In a small bowl, toss the grilling cheese sticks with mayonnaise, half the garlic aioli, and the spice blend. Mix well.", "Fry the grilling cheese: Heat a large pan over medium heat. Fry the cheese sticks without any additional fat for 3-5 min per side until golden brown. Remove from the pan.", "Plate up: Warm the tortilla wraps briefly in the pan. Spread aioli on the tortillas, then top with rocket, caramelized onions, marinated cucumber, and the grilled cheese. Fold and serve."], "source": "hello_fresh_1.pdf"}, {"id": 3, "title": "PRETZEL SALAD WITH GOAT CHEESE BALLS", "subtitle": "with sauteed mushroom and onion mix", "title_de": "BREZNSALAT MIT ZIEGENFRISCHKÄSE-BÄLLCHEN", "prep_time_min": 40, "difficulty": 1, "protein_type": "vegetarian", "ingredients": [{"name_de": "Laugenstangen", "name": "pretzel sticks", "quantity": "125", "unit": "g", "category": "pantry"}, {"name_de": "Ziegenfrischkäsetaler", "name": "fresh goat cheese rounds", "quantity": "125", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Champignons", "name": "white mushrooms", "quantity": "200", "unit": "g", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Karotte", "name": "carrot", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Salatherz (Romana)", "name": "romaine lettuce heart", "quantity": "150", "unit": "g", "category": "produce"}, {"name_de": "Petersilie glatt/Schnittlauch", "name": "flat-leaf parsley / chives", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "mittelscharfer Senf", "name": "Dijon mustard", "quantity": "1", "unit": "EL", "category": "pantry"}, {"name_de": "Worcester Sauce", "name": "Worcestershire sauce", "quantity": "10", "unit": "ml", "category": "pantry"}, {"name_de": "Weißweinessig", "name": "white wine vinegar", "quantity": "15", "unit": "ml", "category": "pantry"}, {"name_de": "Honig", "name": "honey", "quantity": "1", "unit": "TL", "category": "pantry"}, {"name_de": "Olivenöl", "name": "olive oil", "quantity": "2", "unit": "EL", "category": "pantry"}], "steps": ["Prep the vegetables: Keep the goat cheese rounds in the fridge until needed in step 5. Cut the mushrooms into 0.5 cm thick slices. Halve the onion and cut into thin strips. Wash the salad leaves and spin dry.", "Make the pretzel croutons: Heat 1 tbsp [1.5 tbsp | 2 tbsp] oil in a large pan over medium heat. Add the pretzel pieces and toast for 3-5 min until crispy. Remove from the pan and set aside.", "Saute the mushrooms: In the same pan, heat 1 tbsp [1.5 tbsp | 2 tbsp] oil again. Add the onion and mushrooms and saute for 5-7 min until golden. Season with salt, pepper, and thyme. Remove from the pan.", "Make the dressing: In a large bowl, whisk together 1 tbsp [1.5 tbsp | 2 tbsp] water, 1 tbsp [1.5 tbsp | 2 tbsp] honey, vinegar, mustard, and olive oil. Season with salt and pepper.", "Make the goat cheese balls: Finely chop the chives and parsley together and mix two-thirds into the breadcrumbs on a flat plate. Take the goat cheese rounds from the fridge and roll them in the herb breadcrumbs to coat.", "Plate up: Add the salad leaves and remaining herbs to the large bowl and toss with the dressing. Arrange the salad on plates, top with the mushroom-onion mix, pretzel croutons, and the herbed goat cheese balls."], "source": "hello_fresh_1.pdf"}, {"id": 4, "title": "BAKED CHICKEN BREAST PARMIGIANA", "subtitle": "with fettuccine, hard cheese, and tomato sauce", "title_de": "ÜBERBACKENE HÄHNCHENBRUST PARMIGIANA", "prep_time_min": 40, "difficulty": 1, "protein_type": "chicken", "ingredients": [{"name_de": "Hähnchenbrustfilet in Lake", "name": "chicken breast fillet in brine", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Fettuccine", "name": "fettuccine", "quantity": "270", "unit": "g", "category": "pantry"}, {"name_de": "Tomatensugo", "name": "tomato sauce", "quantity": "300", "unit": "g", "category": "pantry"}, {"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Petersilie, glatt", "name": "flat-leaf parsley", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "Hartkäse Ital. Art, gerieben", "name": "grated Italian-style hard cheese", "quantity": "20", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Semmelbrösel", "name": "breadcrumbs", "quantity": "20", "unit": "g", "category": "pantry"}, {"name_de": "Mehl", "name": "flour", "quantity": "25", "unit": "g", "category": "pantry"}, {"name_de": "Ei", "name": "egg", "quantity": "1", "unit": "Stück", "category": "dairy & eggs"}, {"name_de": "Olivenöl", "name": "olive oil", "quantity": "1,5", "unit": "EL", "category": "pantry"}], "steps": ["Prep: Preheat the oven to 220 °C top/bottom heat (200 °C fan). Halve the onion and cut into fine strips. Chop the garlic finely.", "Make the tomato sauce: Heat 1 tbsp [1.5 tbsp | 2 tbsp] olive oil in a small pot. Saute the onion for 2-3 min until soft. Add the garlic and cook for another minute. Stir in the crushed tomatoes and tomato paste, season with salt, pepper, and a pinch of sugar. Let simmer for 10-12 min.", "Bread the chicken: Mix 25 g [50 g | 50 g] flour with salt and a pinch of pepper in a deep plate. Beat the egg in a second deep plate. Mix the breadcrumbs and half the grated hard cheese in a third plate. Slice the chicken breasts in half horizontally to make thin schnitzel. Coat each piece in flour, then egg, then the cheese-breadcrumb mixture.", "Cook the chicken and fettuccine: Heat enough oil in a large ovenproof pan to cover the base. Fry the breaded chicken schnitzel for 3-4 min per side until golden. Bring a large pot of salted water to the boil and cook the fettuccine according to package directions.", "Gratinate the chicken: Spoon 2 tbsp of tomato sauce over each chicken schnitzel and sprinkle with the remaining grated hard cheese. Transfer the pan to the oven and bake for 8-10 min until the cheese is melted and golden.", "Plate up: Drain the fettuccine through a sieve, return to the pot, and toss with the remaining tomato sauce. Divide the pasta onto plates and arrange the chicken parmigiana alongside. Garnish with fresh basil if available."], "source": "hello_fresh_1.pdf"}, {"id": 5, "title": "TUNA BOWL WITH AVOCADO ON LIME RICE", "subtitle": "with cucumber-radish salad, sriracha mayo, and teriyaki sauce", "title_de": "TUNA BOWL MIT AVOCADO AUF LIMETTENREIS", "prep_time_min": 40, "difficulty": 1, "protein_type": "fish", "ingredients": [{"name_de": "Jasminreis", "name": "jasmine rice", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "Skipjack Thunfisch im eigenen Saft", "name": "skipjack tuna in its own juice", "quantity": "160", "unit": "g", "category": "meat & fish"}, {"name_de": "Avocado", "name": "avocado", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Limette, gewachst", "name": "lime", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Radieschen", "name": "radishes", "quantity": "50", "unit": "g", "category": "produce"}, {"name_de": "kleine Salatgurke", "name": "small salad cucumber", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Frühlingszwiebel", "name": "spring onion", "quantity": "20", "unit": "g", "category": "produce"}, {"name_de": "Sesamsamen", "name": "sesame seeds", "quantity": "8", "unit": "g", "category": "pantry"}, {"name_de": "Mayonnaise", "name": "mayonnaise", "quantity": "50", "unit": "g", "category": "pantry"}, {"name_de": "Sriracha Sauce", "name": "sriracha sauce", "quantity": "8", "unit": "ml", "category": "pantry"}, {"name_de": "Teriyakisoße", "name": "teriyaki sauce", "quantity": "50", "unit": "ml", "category": "pantry"}], "steps": ["Cook the rice: Boil 300 ml [450 ml | 600 ml] hot water in a kettle. In a small pot with a lid, combine the hot water with the rice, bring to a boil, reduce heat, cover and cook for 10 min. Turn off the heat and let steam for another 5 min.", "Make the salad: Wash the lime in hot water and finely grate 1 tsp [1.5 tsp | 2 tsp] of the zest. Cut the lime into 6 wedges. Halve the cucumber and cut into 0.5 cm half-moons. Slice the radishes thinly. In a large bowl, combine the cucumber, radishes, a pinch of salt, the juice of 1 [1.5 | 2] lime wedge(s), and a little sugar. Set aside to marinate.", "Make the tuna salad: Drain the tuna using the can lid. In a small bowl, combine the tuna with sriracha mayo and mix well.", "Prepare the avocado: Halve the avocado, remove the pit, and scoop the flesh into a second small bowl. Mash with a fork and season with salt, pepper, and a squeeze of lime juice.", "Cook the teriyaki sauce: In a small pot, combine the teriyaki sauce, juice of 1 [1.5 | 2] lime wedge(s), and 50 ml water. Bring to a simmer and cook for 2-3 min until slightly thickened.", "Plate up: Fluff the rice with a fork and stir in the lime zest. Divide into bowls. Top with the cucumber-radish salad, tuna salad, and mashed avocado. Drizzle with the teriyaki sauce and sriracha mayo."], "source": "hello_fresh_1.pdf"}, {"id": 6, "title": "GIRASOLI IN TOMATO PESTO SAUCE", "subtitle": "with baby spinach, pine nuts, and hard cheese", "title_de": "GIRASOLI IN TOMATEN-PESTO-SOSSE", "prep_time_min": 35, "difficulty": 1, "protein_type": "vegetarian", "ingredients": [{"name_de": "Girasoli mit Tomate Mozzarella", "name": "girasoli pasta with tomato and mozzarella filling", "quantity": "390", "unit": "g", "category": "pantry"}, {"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Oregano, gerebelt", "name": "dried oregano", "quantity": "1,6", "unit": "g", "category": "pantry"}, {"name_de": "Pinienkerne", "name": "pine nuts", "quantity": "10", "unit": "g", "category": "pantry"}, {"name_de": "Tomatenpesto", "name": "tomato pesto", "quantity": "20", "unit": "g", "category": "pantry"}, {"name_de": "stückige Tomaten", "name": "diced tomatoes", "quantity": "390", "unit": "g", "category": "produce"}, {"name_de": "Babyspinat", "name": "baby spinach", "quantity": "100", "unit": "g", "category": "produce"}, {"name_de": "Hartkäse Ital. Art, gerieben", "name": "grated Italian-style hard cheese", "quantity": "20", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Gemüsebrühpulver", "name": "vegetable stock powder", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Olivenöl", "name": "olive oil", "quantity": "1,5", "unit": "EL", "category": "pantry"}], "steps": ["Prep work: Boil plenty of water in a kettle. Dice the onion. Finely chop the garlic. Toast the pine nuts in a dry pan over medium heat for 2-3 min until golden, then set aside.", "Start the sauce: Heat 1 tbsp [1.5 tbsp | 2 tbsp] olive oil in the same pan. Add the garlic, oregano, stock powder, and onion and saute for 2-3 min.", "Cook the pasta: Fill a large pot with plenty of hot water, salt it, and bring to a boil. Add the girasoli and cook according to package directions until al dente. Continue with the recipe.", "Finish the sauce: Add 100 ml tomato pesto and the crushed tomatoes to the pan and let everything simmer for 6-8 min. Season with salt and pepper.", "Finish the pasta: Add the girasoli, spinach, and half the cheese to the large pan with the sauce. Fold gently until the spinach wilts. Season once more.", "Plate up: Divide the girasoli into deep bowls and top with the remaining hard cheese and toasted pine nuts."], "source": "hello_fresh_1.pdf"}, {"id": 7, "title": "CHICKEN LEG WITH PARSLEY CHIMICHURRI", "subtitle": "with Argentinian roasted vegetables", "title_de": "HÄHNCHENKEULE MIT PETERSILIEN-CHIMICHURRI", "prep_time_min": 50, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Hähnchenkeule in Kräutermarinade", "name": "chicken thigh in herb marinade", "quantity": "350", "unit": "g", "category": "meat & fish"}, {"name_de": "Ofenkartoffel", "name": "baking potato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Tomate", "name": "tomato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Zucchini", "name": "zucchini", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Spitzpaprika", "name": "red pointed pepper", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Chilischote", "name": "red chili", "quantity": "0,5", "unit": "Stück", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Petersilie, glatt", "name": "flat-leaf parsley", "quantity": "20", "unit": "g", "category": "produce"}, {"name_de": "Gewürzmischung \"Hello Fiesta\"", "name": "Hello Fiesta spice mix", "quantity": "1", "unit": "EL", "category": "pantry"}, {"name_de": "Zitrone, gewachst", "name": "lemon", "quantity": "0,5", "unit": "Stück", "category": "produce"}, {"name_de": "Olivenöl", "name": "olive oil", "quantity": "3", "unit": "EL", "category": "pantry"}], "steps": ["Sear the legs: Preheat the oven to 220 °C top/bottom heat (200 °C fan). Pat the chicken legs dry and season with salt and pepper. Heat 1 tbsp [1.5 tbsp | 2 tbsp] oil in a large ovenproof pan over high heat. Sear the chicken legs for 2-3 min per side until browned all over.", "Cut the vegetables: Cut the potatoes into 2 cm wedges. Halve the onion, deseed, and cut into 2 cm pieces. Halve the bell peppers, deseed, and cut into 2 cm pieces. Toss the vegetables with 2 tbsp [3 tbsp | 4 tbsp] oil, salt, and pepper on a baking tray lined with parchment paper.", "Into the oven: Add the seared chicken legs to the vegetables on the tray and roast everything together for 25-30 min until the chicken is cooked through and the vegetables are tender.", "Make the chimichurri: Halve the chili, deseed, and cut into very thin strips (caution: hot!). Finely chop the parsley. In a small bowl, combine the red wine vinegar, olive oil, and a pinch of salt.", "Finish the chimichurri: Add the chili strips to taste and all 3 tbsp [4.5 tbsp | 6 tbsp] chopped parsley to the bowl. Stir in the garlic and adjust seasoning.", "Plate up: Divide the roasted vegetables onto plates and arrange the chicken legs alongside. Spoon the chimichurri over the top and serve."], "source": "hello_fresh_1.pdf"}, {"id": 8, "title": "MEXICAN ELOTE-STYLE CORN ON THE COB WITH CHEESE", "subtitle": "on chipotle bean stew with mushrooms", "title_de": "MEXICAN ELOTE-STYLE MAISKOLBEN MIT KÄSE", "prep_time_min": 35, "difficulty": 1, "protein_type": "vegetarian", "ingredients": [{"name_de": "Champignons", "name": "white mushrooms", "quantity": "125", "unit": "g", "category": "produce"}, {"name_de": "schwarze Bohnen", "name": "black beans", "quantity": "400", "unit": "g", "category": "pantry"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Maiskolben (vorgekocht)", "name": "corn on the cob (pre-cooked)", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Chipotle Paste", "name": "chipotle paste", "quantity": "10", "unit": "g", "category": "pantry"}, {"name_de": "Gewürzmischung \"Hello Fiesta\"", "name": "Hello Fiesta spice mix", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Koriander/Petersilie glatt", "name": "cilantro / flat-leaf parsley", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "Hartkäse Ital. Art, gerieben", "name": "grated Italian-style hard cheese", "quantity": "20", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Paniermehl", "name": "breadcrumbs", "quantity": "20", "unit": "g", "category": "pantry"}, {"name_de": "Gemüsebrühpulver", "name": "vegetable stock powder", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Butter", "name": "butter", "quantity": "1", "unit": "TL", "category": "dairy & eggs"}], "steps": ["Prep the vegetables: Boil 300 [450 | 600] ml water in a kettle. Halve or quarter the mushrooms. Halve the onion and cut into fine strips. Finely chop the garlic.", "Get started: Heat 1 tbsp [1.5 tbsp | 2 tbsp] oil in a large pot with a lid. Saute the onion and mushrooms over medium heat for 3-4 min. Add the garlic and cook for 1 more min.", "Season the chipotle beans: Add the beans, chipotle paste, 'Hello Fiesta' spice blend, and stock powder to the pot and stir in the hot water. Bring to a boil, then reduce heat and simmer for 10-12 min.", "Make the cheese crumble: Toast the breadcrumbs in a large pan with 0.5 tbsp [0.75 tbsp | 1 tbsp] oil over medium heat until golden. Add the grated cheese and stir until combined. Remove from heat.", "Fry the corn: Heat 1 tsp [1.5 tsp | 2 tsp] butter in the pan from step 4. Brown the corn cobs all over for 4-5 min. Remove from the pan and set aside.", "Plate up: Divide the chipotle bean stew into deep bowls. Halve the corn cobs and place on top. Sprinkle with the cheese crumble and garnish with spring onion rings and sour cream."], "source": "hello_fresh_1.pdf"}, {"id": 9, "title": "TERIYAKI CHICKEN PAN WITH PAK CHOI", "subtitle": "with bell pepper, served with coconut rice", "title_de": "TERIYAKI-HÄHNCHENPFANNE MIT PAK CHOI", "prep_time_min": 40, "difficulty": 1, "protein_type": "chicken", "ingredients": [{"name_de": "Hähnchenbrustfilet in Lake", "name": "chicken breast fillet in brine", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Basmatireis", "name": "basmati rice", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "Kokosmilch", "name": "coconut milk", "quantity": "180", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Paprika multicolor", "name": "mixed bell peppers", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Pak Choi", "name": "bok choy", "quantity": "200", "unit": "g", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Frühlingszwiebel", "name": "spring onion", "quantity": "20", "unit": "g", "category": "produce"}, {"name_de": "Sojasoße", "name": "soy sauce", "quantity": "1", "unit": "EL", "category": "pantry"}, {"name_de": "Ingwerpaste (im Kühlbeutel)", "name": "ginger paste (chilled)", "quantity": "40", "unit": "ml", "category": "pantry"}, {"name_de": "Teriyakisoße", "name": "teriyaki sauce", "quantity": "40", "unit": "ml", "category": "pantry"}, {"name_de": "Honig", "name": "honey", "quantity": "1", "unit": "TL", "category": "pantry"}], "steps": ["Cook the rice: Boil 200 ml [300 ml | 400 ml] water in a kettle. In a small pot with a lid, combine the coconut milk and hot water. Bring to a boil, stir in the rice, reduce heat, cover, and cook for 10 min. Turn off the heat and let steam for 5 min.", "Meanwhile: Slice the spring onions into thin rings. Halve the bell pepper, deseed, and cut into 1 cm strips. Halve the pak choi lengthwise and cut crosswise into 2 cm pieces.", "Make the teriyaki sauce: Peel the garlic and press into a small bowl. Add the ginger paste, soy sauce, honey, and a little water. Stir to combine.", "Fry the chicken strips: Heat 1 tbsp [1.5 tbsp | 2 tbsp] oil in a large pan over high heat. Season the chicken strips with salt and pepper and fry for 4-5 min until cooked through and lightly browned. Remove from the pan.", "Saute the vegetables: Reduce the heat. Add the bell pepper strips and pak choi to the pan and stir-fry for 3-4 min. Return the chicken to the pan, pour over the teriyaki sauce, and cook for another 2 min.", "Finish the pan: Fluff the rice with a fork and divide onto plates. Top with the teriyaki chicken pan and garnish with spring onion rings."], "source": "hello_fresh_1.pdf"}, {"id": 10, "title": "HOMEMADE PAN DUMPLINGS", "subtitle": "with mushroom goulash", "title_de": "SELBST GEMACHTE PFANNENKNÖDEL", "prep_time_min": 45, "difficulty": 2, "protein_type": "vegetarian", "ingredients": [{"name_de": "Steinofenbaguette", "name": "stone-baked baguette", "quantity": "250", "unit": "g", "category": "pantry"}, {"name_de": "Milch", "name": "milk", "quantity": "250", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Champignons", "name": "white mushrooms", "quantity": "400", "unit": "g", "category": "produce"}, {"name_de": "Porree", "name": "leek", "quantity": "175", "unit": "g", "category": "produce"}, {"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Petersilie glatt/Schnittlauch", "name": "flat-leaf parsley / chives", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "Hartkäse Ital. Art, gerieben", "name": "grated Italian-style hard cheese", "quantity": "25", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Tomatenmark", "name": "tomato paste", "quantity": "10", "unit": "ml", "category": "pantry"}, {"name_de": "Sojasoße", "name": "soy sauce", "quantity": "1", "unit": "EL", "category": "pantry"}, {"name_de": "Gewürzmischung \"Hello Muskat\"", "name": "Hello Muskat spice mix", "quantity": "2", "unit": "g", "category": "pantry"}, {"name_de": "Maisstärke", "name": "cornstarch", "quantity": "1", "unit": "EL", "category": "pantry"}, {"name_de": "Ei", "name": "egg", "quantity": "1", "unit": "Stück", "category": "dairy & eggs"}], "steps": ["Prep work: Halve the onion; cut one half into very thin strips and finely dice the other half. Finely chop the garlic. Cut the mushrooms into 0.5 cm slices. Finely chop the fresh herbs (reserving some for garnish).", "Make the dumpling mixture: In a large bowl, combine the baguette cubes, herbs (reserving a few for garnish), eggs, warm milk, salt, pepper, and nutmeg. Mix well and let soak for 10 min.", "Fry the pan dumplings: With damp hands, shape the dumpling mixture into 8 [12 | 16] patties about 1 cm thick. Heat 1 tbsp [1.5 tbsp | 2 tbsp] oil in a large pan over medium heat and fry the patties for 4-5 min per side until golden brown. Remove from the pan and keep warm.", "Meanwhile: Halve the leek lengthwise, wash thoroughly, and slice only the white and light green parts into 1 cm rings. In the same pan, heat 1 tbsp oil and saute the diced onion and sliced onion for 2 min. Add the mushrooms and leek and cook for 5-6 min until softened.", "Finish the mushroom goulash: Add half [two-thirds | all] of the tomato paste, soy sauce, half [two-thirds | all] of the broth, and the spice blend to the pan. Stir to combine and let simmer for 5 min. Stir in the sour cream and season with salt and pepper.", "Plate up: Arrange the pan dumplings and mushroom goulash on plates. Enjoy!"], "source": "hello_fresh_1.pdf"}, {"id": 11, "title": "FISH FILLET FINKENWERDER STYLE WITH BACON", "subtitle": "oven potatoes and apple-carrot salad", "title_de": "FISCHFILET FINKENWERDER ART MIT SPECK", "prep_time_min": 40, "difficulty": 2, "protein_type": "fish", "ingredients": [{"name_de": "Seelachs ohne Haut", "name": "skinless pollock", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "vorw. festk. Kartoffeln", "name": "waxy potatoes", "quantity": "400", "unit": "g", "category": "produce"}, {"name_de": "Chorizo", "name": "chorizo", "quantity": "75", "unit": "g", "category": "meat & fish"}, {"name_de": "Apfel", "name": "apple", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Karotte", "name": "carrot", "quantity": "400", "unit": "g", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Dill/Petersilie", "name": "dill / parsley", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "Naturjoghurt", "name": "plain yogurt", "quantity": "120", "unit": "g", "category": "dairy & eggs"}], "steps": ["Prep work: Preheat the oven to 220 °C top/bottom heat (200 °C fan). Peel the potatoes and cut into 0.5 cm thick slices. Halve the onion and cut into wedges.", "Make the oven potatoes: Spread the potato slices and onion wedges on a baking tray lined with parchment paper. Toss with 1 tbsp [1.5 tbsp | 2 tbsp] oil, salt, and pepper. Bake in the oven for 20-25 min until golden.", "Prep the vegetables: Coarsely grate the apple and carrot and place in a large bowl. Finely chop the dill tips.", "Finish the salad: Toss the apple and carrot with the yogurt and dill. Season with sugar, salt, and pepper.", "Fry the fish: Cut the chorizo into 1 cm cubes. About 10 min before the potatoes are done, heat 1 tbsp oil in a large pan over medium heat. Fry the chorizo for 2-3 min. Season the fish fillets on both sides with salt and pepper and add to the pan. Fry for 3-4 min per side until cooked through.", "Plate up: Arrange the fish with the chorizo, apple-carrot salad, and oven potatoes on plates. Garnish with parsley."], "source": "hello_fresh_1.pdf"}, {"id": 12, "title": "FETTUCCINE WITH HONEY GOAT CHEESE CRUMBLE", "subtitle": "with caramelized oyster mushrooms in aromatic thyme sauce", "title_de": "FETTUCCINE MIT HONIG-ZIEGENKASE-CRUMBLE", "prep_time_min": 40, "difficulty": 2, "protein_type": "vegetarian", "ingredients": [{"name_de": "Fettuccine", "name": "fettuccine", "quantity": "270", "unit": "g", "category": "pantry"}, {"name_de": "Krauterseitlinge", "name": "king oyster mushrooms", "quantity": "300", "unit": "g", "category": "produce"}, {"name_de": "Babyspinат", "name": "baby spinach", "quantity": "100", "unit": "g", "category": "produce"}, {"name_de": "Petersilie/Thymian", "name": "parsley / thyme", "quantity": "1", "unit": "Bund", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Ziegenkase-Crumble mit Honig", "name": "goat cheese crumble with honey", "quantity": "100", "unit": "g", "category": "pantry"}, {"name_de": "Gemüsebrühpulver", "name": "vegetable stock powder", "quantity": "10", "unit": "g", "category": "pantry"}, {"name_de": "milder Chili Mix", "name": "mild chili blend", "quantity": "1", "unit": "TL", "category": "produce"}], "steps": ["Prep work: Boil plenty of water in a kettle. Quarter the oyster mushrooms lengthwise. Finely chop the parsley. In a small bowl, crumble the goat cheese and mix with the breadcrumbs to form a crumble.", "Saute the mushrooms: Heat 1 tbsp oil in a large pan. Reduce the heat, add 1 tsp honey, and add the mushroom quarters. Saute for 5-6 min over medium heat until golden and caramelized. Season with salt and thyme. Remove from the pan and set aside.", "Cook the pasta: Add the pasta to the boiling water and cook for 9-11 min until al dente. Continue with the recipe.", "Make the sauce: Heat 1 tbsp oil in the pan from step 2. Measure out 150 ml of pasta cooking water and set aside. Add the garlic and cook briefly. Deglaze with the pasta water, add the cream, and let reduce slightly.", "Finish the pasta: Drain the pasta through a sieve and add it while still hot to the sauce in the pan. Add the baby spinach and toss everything together until the spinach wilts. Season with salt and pepper.", "Plate up: Divide the pasta into deep bowls. Top with the remaining goat cheese crumble and the caramelized oyster mushrooms. Garnish with parsley."], "source": "hello_fresh_3.pdf"}, {"id": 13, "title": "CHICKEN PICCATA IN CAPER LEMON SAUCE", "subtitle": "with green beans and oven baby potatoes", "title_de": "HAHNCHEN PICCATA IN KAPERN-ZITRONEN-SOSSE", "prep_time_min": 35, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Hahnchenbrustfilet in Lake", "name": "chicken breast fillet in brine", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Kartoffeln (Drillinge)", "name": "baby potatoes", "quantity": "300", "unit": "g", "category": "produce"}, {"name_de": "Buschbohnen", "name": "green beans", "quantity": "400", "unit": "g", "category": "pantry"}, {"name_de": "Zitrone, gewachst", "name": "lemon", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Gewürzmischung 'Hello Buon Appetito'", "name": "Hello Buon Appetito spice mix", "quantity": "1", "unit": "TL", "category": "pantry"}, {"name_de": "Maisstärke", "name": "cornstarch", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Kapern", "name": "capers", "quantity": "35", "unit": "g", "category": "pantry"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Hühnerbrühe", "name": "chicken stock", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stuck", "category": "produce"}], "steps": ["Bake the potatoes: Preheat the oven to 220 °C top/bottom heat. Boil 1 L water in a kettle. Halve or quarter the baby potatoes. Toss with 1 tbsp [1.5 tbsp | 2 tbsp] oil, salt, and pepper on a baking tray lined with parchment paper. Bake for 20-25 min until golden.", "Prep work: Trim the ends of the green beans and halve them. Finely chop the garlic and onion. Cut the lemon into wedges. Pound the chicken breasts between sheets of plastic wrap until thin.", "Cook the beans: Fill a large pot with 1 L hot water, add 1 tbsp salt, and bring to the boil. Cook the green beans for 8-9 min until just tender. Drain and set aside.", "Fry the chicken: In a tall mixing bowl, whisk together 150 ml water, chicken broth, and cornstarch. In a large pan, heat 1 tbsp [1.5 tbsp | 2 tbsp] oil over medium-high heat. Coat the chicken in flour, shake off the excess, then fry for 3-4 min per side until cooked through. Remove from the pan.", "Finish the sauce: Deglaze the pan with the prepared broth mixture. Add the capers, onion, and garlic and cook for 2-3 min. Squeeze in the juice of 1 (2) lemon wedge(s) and stir in 1 tbsp [1.5 tbsp | 2 tbsp] butter. Season with salt and pepper.", "Plate up: Serve the baby potatoes and green beans on plates. Arrange the chicken piccata alongside and drizzle with the caper lemon sauce."], "source": "hello_fresh_3.pdf"}, {"id": 14, "title": "MEXICAN SPICY PULLED CHICKEN CHIPOTLE SOUP", "subtitle": "with corn, sour cream, and coriander", "title_de": "MEXIKANISCHE SPICY PULLED CHICKEN CHIPOTLE SUPPE", "prep_time_min": 35, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Hähnchenbrustfilet in Lake", "name": "chicken breast fillet in brine", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "stückige Tomaten", "name": "diced tomatoes", "quantity": "390", "unit": "g", "category": "produce"}, {"name_de": "Chipotle Paste", "name": "chipotle paste", "quantity": "8", "unit": "g", "category": "pantry"}, {"name_de": "saure Sahne, Bio", "name": "organic sour cream", "quantity": "100", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Ofenkartoffel", "name": "baking potato", "quantity": "350", "unit": "g", "category": "produce"}, {"name_de": "Mais", "name": "corn", "quantity": "140", "unit": "g", "category": "produce"}, {"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Koriander", "name": "cilantro", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "Hühnerbrühe", "name": "chicken stock", "quantity": "1", "unit": "Stuck", "category": "pantry"}], "steps": ["Sear the chicken: Boil plenty of water in a kettle. Heat 1 tbsp oil in a large pot with a lid over high heat. Season the chicken breasts with salt and pepper and sear for 2-3 min per side. Pour in 400 ml hot water, cover, and cook over medium heat for 15 min.", "Prep work: Meanwhile, peel the potatoes and cut into 1 cm cubes. Roughly dice the onion. Finely chop the garlic.", "Shred the chicken: Remove the chicken from the pot and shred it in a large bowl using two forks. Set the cooking liquid aside.", "Start the soup: Add the onion, chipotle paste, tomato paste, potatoes, and stock powder to the pot along with the reserved cooking liquid and 300 ml hot water. Bring to a boil and cook for 15-20 min until the potatoes are tender.", "Finish the soup: Finely chop the coriander. Add the corn and shredded chicken to the soup and cook until heated through. Season with salt, pepper, and a squeeze of lime.", "Plate up: Divide the chipotle chicken soup into deep bowls. Garnish with sour cream and chopped coriander."], "source": "hello_fresh_3.pdf"}, {"id": 15, "title": "CRISPY CHICKEN AND FRIES FROM THE AIR FRYER", "subtitle": "air fryer required for preparation", "title_de": "CRISPY CHICKEN & POMMES AUS DEM AIR-FRYER", "prep_time_min": 35, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Hähnchenbrustfilet in Lake", "name": "chicken breast fillet in brine", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Gewürzmischung 'Hello Paprika'", "name": "Hello Paprika spice mix", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Mayonnaise", "name": "mayonnaise", "quantity": "40", "unit": "g", "category": "pantry"}, {"name_de": "Pommes Frites", "name": "french fries", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "kleine Salatgurke", "name": "small salad cucumber", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Pankomel", "name": "panko breadcrumbs", "quantity": "25", "unit": "g", "category": "pantry"}, {"name_de": "Honig-Senf-Dressing", "name": "honey mustard dressing", "quantity": "25", "unit": "g", "category": "pantry"}, {"name_de": "Salatherz (Romana)", "name": "romaine lettuce heart", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Zitrone", "name": "lemon", "quantity": "0,5", "unit": "Stuck", "category": "produce"}], "steps": ["Cook the fries: Place the fries in the air fryer basket and lightly season with salt. Cook at 200 °C for 15-18 min, shaking halfway through, until golden and crispy.", "Bread the chicken: In a large bowl, toss the chicken breast fillet with 'Hello Paprika' spice blend and half the mayonnaise to coat. Place the breadcrumbs on a flat plate and press the chicken into the crumbs to coat on all sides.", "Prep work: Cut the lettuce into strips. Cut the cucumber into 1 cm half-moons.", "Bake the chicken: Place the breaded chicken fillet in the air fryer basket and bake at 200 °C for 10 min, then flip and bake for another 5-8 min until cooked through and crispy.", "Make the salad: Meanwhile, in a small bowl, mix together the honey mustard dressing, remaining mayonnaise, and a pinch of salt to make the dip. In a large bowl, toss the lettuce strips and cucumber with the dressing.", "Plate up: Divide the fries, salad, and crispy chicken fillets onto plates and serve with the dip."], "source": "hello_fresh_3.pdf"}, {"id": 16, "title": "SALMON IN HONEY SOY GLAZE", "subtitle": "with sesame potatoes and pear salad", "title_de": "LACHS IN HONIG-SOJA-GLASUR", "prep_time_min": 35, "difficulty": 1, "protein_type": "fish", "ingredients": [{"name_de": "Lachsfilet", "name": "salmon fillet", "quantity": "200", "unit": "g", "category": "meat & fish"}, {"name_de": "vorw. festk. Kartoffeln", "name": "waxy potatoes", "quantity": "400", "unit": "g", "category": "produce"}, {"name_de": "Salatherz (Romana)", "name": "romaine lettuce heart", "quantity": "150", "unit": "g", "category": "produce"}, {"name_de": "Sesamkörner", "name": "sesame seeds", "quantity": "10", "unit": "g", "category": "pantry"}, {"name_de": "Schalotte", "name": "shallot", "quantity": "2", "unit": "Stuck", "category": "produce"}, {"name_de": "Birne", "name": "pear", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Sojasoße", "name": "soy sauce", "quantity": "20", "unit": "ml", "category": "pantry"}, {"name_de": "Soja-Sauce", "name": "soy sauce", "quantity": "2", "unit": "EL", "category": "pantry"}, {"name_de": "Balsamicoessig", "name": "balsamic vinegar", "quantity": "3", "unit": "EL", "category": "pantry"}, {"name_de": "Honig", "name": "honey", "quantity": "2", "unit": "EL", "category": "pantry"}], "steps": ["Roast the potatoes: Halve the potatoes and cut into 1 cm wedges. Spread on a baking tray lined with parchment paper, toss with 1 tbsp [1.5 tbsp | 2 tbsp] oil, sesame seeds, salt, and pepper. Roast in the oven at 200 °C for 20-25 min until golden.", "Prep work: Finely dice the shallot. Tear the salad leaves into bite-sized pieces. Quarter the pear, remove the core, and cut into thin slices.", "Make the sauce: Press the garlic into a small bowl. Add the soy sauce, 2 tbsp honey, 4 tbsp balsamic vinegar, and a little water. Stir to combine.", "Fry the salmon: Season the salmon fillets on both sides with salt. Heat 1 tbsp oil in a large pan over medium-high heat. Add the salmon and fry for 3-4 min per side until cooked to your liking. Pour the sauce over the salmon and let it glaze for 1-2 min.", "Make the salad: In a large bowl, combine the shallot, a little vinegar, oil, salt, and pepper to make a dressing. Add the salad leaves and pear slices and toss to coat.", "Plate up: Divide the salmon, pear salad, and sesame potatoes onto plates. Drizzle any remaining glaze over the salmon."], "source": "hello_fresh_3.pdf"}, {"id": 17, "title": "FRUITY AND SPICY CHICKEN BOWL WITH RICE", "subtitle": "on fresh mango-bell pepper salad and lime yogurt", "title_de": "FRUCHTIG-SCHARFE HAHNCHEN-BOWL MIT REIS", "prep_time_min": 35, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Basmatieis", "name": "basmati rice", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "Hähnchenschnetzeltes", "name": "chicken strips", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Mango", "name": "mango", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "rote Spitzpaprika", "name": "red pointed pepper", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Gewürzmischung 'Hello Aloha'", "name": "Hello Aloha spice mix", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Jalapeno", "name": "jalapeño", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Limette, gewachst", "name": "lime", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Naturjoghurt", "name": "plain yogurt", "quantity": "75", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Hänchengeschnetzeltes", "name": "chicken strips", "quantity": "100", "unit": "g", "category": "meat & fish"}], "steps": ["Cook the rice: Boil plenty of water in a kettle. In a small pot with a lid, combine 300 ml hot water with the rice, bring to a boil, reduce heat, cover, and cook for 10 min. Turn off the heat and let steam for 5 min.", "Prep work: Halve the bell pepper, deseed, and cut into 1 cm cubes. Halve the jalapeno, deseed, and finely chop. Peel and dice the mango. Juice the lime.", "Make the dressing: In a large bowl, whisk together the lime juice, 1 tbsp oil, 1 tsp yogurt, 1 tbsp lime juice, salt, and pepper.", "Fry the chicken: Heat 1 tbsp oil in a large pan over high heat. Add the chicken strips, bell pepper, and remaining spice blend. Fry for 5-6 min until the chicken is cooked through and lightly browned.", "Finish the chicken: Add the chicken and vegetables to the large bowl with the dressing. Let marinate briefly, then add the diced mango and fold to combine.", "Plate up: Divide the rice onto plates and fluff with a fork. Top with the chicken and mango salad. Garnish with yogurt, lime zest, and jalapeno to taste."], "source": "hello_fresh_3.pdf"}, {"id": 18, "title": "SWEET POTATO AND LEEK SOUP WITH CHICKEN", "subtitle": "prepared in air fryer or pan", "title_de": "SÜSSKARTOFFEL-LAUCH-SUPPE MIT HAHNCHEN", "prep_time_min": 35, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Hähnchenbrustfilet in Lake", "name": "chicken breast fillet in brine", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Süsskartoffel", "name": "sweet potato", "quantity": "375", "unit": "g", "category": "produce"}, {"name_de": "Karotte", "name": "carrot", "quantity": "22", "unit": "g", "category": "produce"}, {"name_de": "Porree", "name": "leek", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Knoblauch-Ingwer-Zitronengras-Paste", "name": "garlic, ginger and lemongrass paste", "quantity": "8", "unit": "ml", "category": "pantry"}, {"name_de": "Sriracha Sauce", "name": "sriracha sauce", "quantity": "8", "unit": "ml", "category": "pantry"}, {"name_de": "Sweet Chili Sosse", "name": "sweet chili sauce", "quantity": "25", "unit": "g", "category": "pantry"}, {"name_de": "Kokosmilch", "name": "coconut milk", "quantity": "90", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Hühnerbrühe", "name": "chicken stock", "quantity": "1", "unit": "Stuck", "category": "pantry"}, {"name_de": "Frühlingszwiebel", "name": "spring onion", "quantity": "2", "unit": "Stuck", "category": "produce"}], "steps": ["Prep work: Boil 450 ml water in a kettle. Peel the sweet potato and carrots and cut into 1 cm cubes. Slice the leek into 1 cm rings. Finely chop the garlic.", "Saute the vegetables: Heat 0.5 tbsp oil in a large pot with a lid. Add the sweet potato, carrot, and leek and saute over medium heat for 3-4 min.", "Start the soup: Pour 450 ml hot water over the vegetables and cook, covered, for 11-16 min until tender. Continue with the recipe.", "Cook the chicken in the air fryer: In a large bowl, toss the chicken with sweet chili sauce, sriracha, 0.5 tbsp oil, 'Salt' spice blend, salt, and pepper. Place in the air fryer basket and cook at 200 °C for 10-12 min until cooked through.", "Blend the soup: After the vegetables are tender, use a hand blender to blend half the soup until creamy. Stir in the coconut milk and season with salt, pepper, and a squeeze of lime.", "Plate up: Divide the soup into deep bowls. Slice the chicken breast if desired and place on top. Garnish with spring onion rings and a drizzle of sriracha."], "source": "hello_fresh_3.pdf"}, {"id": 19, "title": "CAMEMBERT EN CROUTE WITH CARAMELIZED ONION", "subtitle": "prepared in air fryer or pan", "title_de": "CAMEMBERT EN CROUTE MIT KARAMELLISIERTER ZWIEBEL", "prep_time_min": 50, "difficulty": 3, "protein_type": "vegetarian", "ingredients": [{"name_de": "Camembert", "name": "camembert", "quantity": "125", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Frischer Butter-Blatterteig", "name": "fresh butter puff pastry", "quantity": "50", "unit": "g", "category": "dairy & eggs"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "280", "unit": "g", "category": "produce"}, {"name_de": "Apfel", "name": "apple", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "rote Spitzpaprika", "name": "red pointed pepper", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "vorw. festk. Kartoffeln", "name": "waxy potatoes", "quantity": "400", "unit": "g", "category": "produce"}, {"name_de": "Blattsalatmischung", "name": "mixed salad leaves", "quantity": "1", "unit": "Bund", "category": "produce"}, {"name_de": "Thymian, gerieben", "name": "dried thyme", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "mittelsch. Senf", "name": "Dijon mustard", "quantity": "1", "unit": "TL", "category": "pantry"}, {"name_de": "Balsamicoessig", "name": "balsamic vinegar", "quantity": "2", "unit": "EL", "category": "pantry"}], "steps": ["First steps: Quarter or halve the potatoes. Fill a large pot with water, add 1 tsp salt, and bring to the boil. Cook the potatoes for 15-18 min until tender. Drain and set aside.", "Saute the apple: Heat 1 tbsp butter in a large pan. Add the apple and onions and saute for 2-3 min. Add a pinch of sugar and cook for another 2-3 min until lightly caramelized. Season with salt and pepper.", "For the air fryer: Lay out the puff pastry squares. Place the camembert, apple, and onion mixture in the center of each square.", "Final air fryer step: Fold the pastry corners up and press together to seal. Cook in the air fryer at 180 °C for 10-12 min until the pastry is golden and crispy.", "Make the salad: In a large bowl, whisk together 1 tbsp oil, 1 tbsp balsamic vinegar, 1 tsp mustard, salt, and pepper. Add the salad leaves and toss to coat.", "Plate up: Arrange the salad and potatoes alongside the pastry parcels on plates. Enjoy!"], "source": "hello_fresh_3.pdf"}, {"id": 20, "title": "HAZELNUT CHICKEN NUGGETS", "subtitle": "with celery-potato mash and oven-roasted carrots", "title_de": "HASELNUSS-HAHNCHEN-NUGGETS", "prep_time_min": 40, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Hähnchenbrustfilet in Lake", "name": "chicken breast fillet in brine", "quantity": "175", "unit": "g", "category": "meat & fish"}, {"name_de": "Ofenkartoffel", "name": "baking potato", "quantity": "350", "unit": "g", "category": "produce"}, {"name_de": "Karotte", "name": "carrot", "quantity": "150", "unit": "g", "category": "produce"}, {"name_de": "Knollensellerie", "name": "celeriac", "quantity": "20", "unit": "g", "category": "produce"}, {"name_de": "Gewürzmischung 'Hello Paprika'", "name": "Hello Paprika spice mix", "quantity": "5", "unit": "g", "category": "pantry"}, {"name_de": "Gewürzmischung 'Hello Muskat'", "name": "Hello Muskat spice mix", "quantity": "5", "unit": "g", "category": "pantry"}, {"name_de": "Haselnusskerne, geroostet, ganz", "name": "whole roasted hazelnuts", "quantity": "75", "unit": "g", "category": "pantry"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Naturjoghurt", "name": "plain yogurt", "quantity": "150", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Frühlingszwiebel", "name": "spring onion", "quantity": "2", "unit": "Stuck", "category": "produce"}, {"name_de": "Hartkase ital. Art, gerieben", "name": "grated Italian-style hard cheese", "quantity": "20", "unit": "g", "category": "dairy & eggs"}], "steps": ["Prep the vegetables: Boil plenty of water in a kettle. Peel the carrots, halve crosswise, and cut lengthwise into quarters. Peel and dice the potatoes and celeriac into 2 cm pieces. Cut the chicken breast into bite-sized pieces.", "Bread the chicken: In a second deep plate, blitz the hazelnuts and grated hard cheese with a hand blender until finely ground. Season with salt and pepper. Beat the egg in a separate bowl. Dip the chicken pieces first in the egg, then in the hazelnut-cheese mixture.", "Bake the nuggets: Spread the carrots, white spring onion rings, and garlic on one half of a baking tray lined with parchment paper. Drizzle with 1 tbsp [1.5 tbsp | 2 tbsp] oil and season with salt and pepper. Arrange the breaded nuggets on the other half. Bake at 200 °C for 18-20 min until the nuggets are golden and cooked through.", "Cook the celeriac and potatoes: Fill a large pot with plenty of hot water and cook the potatoes and celeriac for 12-15 min until tender.", "Finish the mash: Drain the celeriac and potatoes through a sieve, reserving some of the cooking water. Return to the pot and mash with butter, a splash of cooking water, salt, pepper, and nutmeg until smooth.", "Plate up: Arrange the chicken nuggets, oven carrots, and celeriac-potato mash on plates. Garnish with the green spring onion rings."], "source": "hello_fresh_3.pdf"}, {"id": 21, "title": "CASHEW CURRY CHICKEN PAN", "subtitle": "with mushrooms, served with leek rice", "title_de": "CASHEW-CURRY-HAHNCHEN PFANNE", "prep_time_min": 30, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Basmatieis", "name": "basmati rice", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "Hühnerbrühe", "name": "chicken stock", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Gewürzmischung 'Hello Curry'", "name": "Hello Curry spice mix", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Hänchengeschnetzeltes", "name": "chicken strips", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Champignons", "name": "white mushrooms", "quantity": "125", "unit": "g", "category": "produce"}, {"name_de": "Cashewkerne, geroostet", "name": "roasted cashews", "quantity": "40", "unit": "g", "category": "pantry"}, {"name_de": "Sojasosse", "name": "soy sauce", "quantity": "20", "unit": "ml", "category": "pantry"}, {"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Porree", "name": "leek", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Maisstärke", "name": "cornstarch", "quantity": "4", "unit": "g", "category": "pantry"}], "steps": ["Prep work: Boil 300 ml water in a kettle. Halve the leek and slice into 1 cm half-moons. In a small pot with a lid, combine the hot water, coconut milk, and a pinch of salt. Bring to a boil, add the rice and leek, reduce heat, cover, and cook for 10 min. Turn off the heat and let steam.", "Cook the leek rice: Stir the rice and leek together and cook over low heat for 10 min. Turn off and allow to steam.", "Meanwhile: Halve or quarter the mushrooms. Roughly chop the cashews. Halve the onion and cut into strips. Cut the chicken breast into 1 cm strips.", "Fry the meat: Heat 1 tbsp oil and 1 tbsp butter in a large pan. Add the mushrooms, onion, and chicken strips and fry over high heat for 5-6 min until cooked through and golden. Remove from the pan.", "Finish the chicken: Season the pan contents with chicken broth and 'Hello Curry' spice blend. Add the soy sauce and 200 ml water and let reduce for 3-4 min. Stir in the cooking cream and return the chicken to the pan.", "Plate up: Fluff the rice with a fork after cooking and divide into deep bowls. Top with the cashew curry chicken and garnish with spring onion rings and chopped cashews."], "source": "hello_fresh_3.pdf"}, {"id": 22, "title": "TEX-MEX CORN CREAM SOUP WITH CHICKEN", "subtitle": "with tortilla chips, topped with chili and sour cream", "title_de": "TEX-MEX MAISCRÉMESUPPE MIT HAHNCHEN", "prep_time_min": 40, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Schalotte", "name": "shallot", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Porree", "name": "leek", "quantity": "250", "unit": "g", "category": "produce"}, {"name_de": "Hänchengeschnetzeltes", "name": "chicken strips", "quantity": "150", "unit": "g", "category": "meat & fish"}, {"name_de": "Hühnerbrühe", "name": "chicken stock", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Gewürzmischung 'Hello Smoky Paprika'", "name": "Hello Smoky Paprika spice mix", "quantity": "6", "unit": "g", "category": "pantry"}, {"name_de": "Mais", "name": "corn", "quantity": "285", "unit": "g", "category": "produce"}, {"name_de": "saure Sahne, Bio", "name": "organic sour cream", "quantity": "75", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Tortilla-Chips", "name": "tortilla chips", "quantity": "8", "unit": "g", "category": "pantry"}, {"name_de": "rote Chillischote", "name": "red chili", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stuck", "category": "produce"}], "steps": ["Prep the vegetables: Boil 400 ml water in a kettle. Halve the leek lengthwise, wash thoroughly, and separate the green and white parts. Cut the white and pale green parts into 1 cm rings. Finely chop the garlic and shallots. Drain the corn.", "Saute the vegetables: Heat 1 tbsp oil in a large pot with a lid. Add the green leek rings and saute for 2-3 min. Remove and set aside for garnish.", "Fry the chicken: Heat 1 tbsp oil again in the pot. Add the chicken strips and fry for 3-4 min until cooked through, turning occasionally. Season with salt and pepper and remove from the pot.", "Make the soup: Heat 1 tbsp oil in the pot again. Add the leek pieces, garlic, and shallots and saute for 2-3 min. Add the corn (reserving some for garnish), hot water, and stock powder. Bring to a boil and cook for 10-12 min.", "Finish the soup: When the leek is soft, stir in the sour cream. Add the remaining corn along with the liquid and blend with a hand blender until smooth. Return the chicken to the soup.", "Plate up: Divide the soup into bowls. Garnish with the remaining sour cream, green leek rings, chicken pieces, and tortilla chips as desired."], "source": "hello_fresh_3.pdf"}, {"id": 23, "title": "TERIYAKI CHICKEN PAN WITH LEEK", "subtitle": "with bell pepper, served with coconut rice", "title_de": "TERIYAKI-HAHNCHENPFANNE MIT PORREE", "prep_time_min": 40, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Hähnchenbrustfilet in Lake", "name": "chicken breast fillet in brine", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Basmatieis", "name": "basmati rice", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "Kokosmilch", "name": "coconut milk", "quantity": "180", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Paprika multicolor", "name": "mixed bell peppers", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "Sojasosse", "name": "soy sauce", "quantity": "20", "unit": "ml", "category": "pantry"}, {"name_de": "Frühlingszwiebel", "name": "spring onion", "quantity": "2", "unit": "Stuck", "category": "produce"}, {"name_de": "Ingwerpaste (im Kuhlbeutel)", "name": "ginger paste (chilled)", "quantity": "10", "unit": "g", "category": "pantry"}, {"name_de": "Porree", "name": "leek", "quantity": "1", "unit": "Stuck", "category": "produce"}], "steps": ["Cook the rice: Boil 300 ml water in a kettle. In a small pot with a lid, combine the coconut milk and 300 ml hot water. Bring to a boil, stir in the rice, reduce heat, cover, and cook for 10 min. Turn off the heat and let steam for 5 min.", "Meanwhile: Slice the spring onion into small rings. Halve the bell pepper, deseed, and cut into 1 cm strips. Halve the leek lengthwise, wash, and slice into 1 cm rings. Cut the chicken breast into 1 cm strips.", "Make the teriyaki sauce: Peel the garlic and press into a small bowl. Add the ginger paste, soy sauce, honey, and a splash of water. Stir to combine.", "Fry the chicken strips: Heat 1 tbsp oil in a large pan over high heat. Add the chicken strips and fry for 4-5 min until cooked through and golden. Season with salt and pepper. Remove from the pan.", "Saute the vegetables: Reduce the heat, add the bell pepper strips and leek to the pan, and stir-fry for 3-4 min. Return the chicken to the pan, pour over the teriyaki sauce, and cook for another 2 min until the sauce coats everything.", "Finish the pan: Fluff the rice with a fork and divide onto plates. Top with the teriyaki chicken pan. Garnish with spring onion rings."], "source": "hello_fresh_3.pdf"}, {"id": 24, "title": "GLAZED SRIRACHA SHRIMP ON LIME RICE", "subtitle": "with kiwi-cucumber salsa and coconut flakes", "title_de": "GLAZED SRIRACHA SHRIMPS AUF LIMETTENREIS", "prep_time_min": 35, "difficulty": 2, "protein_type": "seafood", "ingredients": [{"name_de": "Jasminreis", "name": "jasmine rice", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "Grossgarnelen", "name": "king prawns", "quantity": "150", "unit": "g", "category": "meat & fish"}, {"name_de": "Kokosraspeln", "name": "desiccated coconut", "quantity": "8", "unit": "g", "category": "pantry"}, {"name_de": "Sojasosse", "name": "soy sauce", "quantity": "8", "unit": "ml", "category": "pantry"}, {"name_de": "Sweet Chili Sosse", "name": "sweet chili sauce", "quantity": "50", "unit": "g", "category": "pantry"}, {"name_de": "Sriracha Sauce", "name": "sriracha sauce", "quantity": "8", "unit": "ml", "category": "pantry"}, {"name_de": "Maisstärke", "name": "cornstarch", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Kiwi", "name": "kiwi", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "kleine Salatgurke", "name": "small salad cucumber", "quantity": "1", "unit": "Stuck", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "0,5", "unit": "Stuck", "category": "produce"}, {"name_de": "Limette, gewachst", "name": "lime", "quantity": "1", "unit": "Stuck", "category": "produce"}], "steps": ["Cook the rice: Boil 300 ml water in a kettle. In a small pot with a lid, combine the coconut milk and 300 ml hot water. Bring to a boil, stir in the rice, reduce heat, cover, and cook for 10 min. Turn off the heat and let steam for 5 min.", "Prep work: Peel the kiwi and cut into 0.5 cm cubes. Cut the cucumber into 0.5 cm cubes. Finely slice the spring onion rings. Juice the lime and grate the zest.", "Make the salsa: In a large bowl, combine the lime juice, 1 tbsp oil, 1.5 tbsp lime juice, salt, and pepper. Add the kiwi, cucumber, and spring onion and toss to combine. Set aside.", "Make the sauce: In a tall mixing bowl, whisk together 100 ml water, cornstarch, soy sauce, sweet chili sauce, sriracha, and a pinch of sugar until smooth.", "Fry the shrimp: Heat 1 tbsp oil in the same large pan. Add the shrimp and onions and fry for 2-3 min until the shrimp turn pink. Pour the sauce over the shrimp and let simmer for 1-2 min until the sauce thickens into a glaze.", "Plate up: Divide the rice into deep bowls, fluff with a fork, and stir in the lime zest. Top with the glazed sriracha shrimp and the kiwi-cucumber salsa. Sprinkle with coconut flakes."], "source": "hello_fresh_3.pdf"}, {"id": 25, "title": "WARM POTATO SALAD WITH BABY SPINACH", "subtitle": "at least -20% calories compared to the other recipes", "title_de": "Warmer Kartoffelsalat mit Babyspinat", "prep_time_min": 40, "difficulty": 2, "protein_type": "vegetarian", "ingredients": [{"name_de": "Babyspinat", "name": "baby spinach", "quantity": "150", "unit": "g", "category": "produce"}, {"name_de": "Kürbiskerne", "name": "pumpkin seeds", "quantity": "10", "unit": "g", "category": "pantry"}, {"name_de": "Mayonnaise", "name": "mayonnaise", "quantity": "20", "unit": "ml", "category": "pantry"}, {"name_de": "Rotweinessig", "name": "red wine vinegar", "quantity": "20", "unit": "ml", "category": "pantry"}, {"name_de": "Gurke", "name": "cucumber", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Honig", "name": "honey", "quantity": "1", "unit": "TL", "category": "pantry"}, {"name_de": "Kirschtomaten", "name": "cherry tomatoes", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Joghurt", "name": "yogurt", "quantity": "75", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Kartoffeln (Drillinge)", "name": "baby potatoes", "quantity": "600", "unit": "g", "category": "produce"}, {"name_de": "Mozzarella", "name": "mozzarella", "quantity": "100", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}], "steps": ["Cut the unpeeled potatoes into quarters lengthwise and spread on a baking tray lined with parchment paper. Drizzle with 1 tbsp [1.5 tbsp | 2 tbsp] oil and season with salt, pepper, and paprika. Roast in the oven at 200 °C for 25-30 min until golden.", "Trim the ends of the cucumber, halve, and cut into 0.5 cm half-moons. Halve the cherry tomatoes. Place the cucumber and tomatoes in a large bowl.", "Press the garlic (to taste) into a small bowl and mix with mayonnaise, pumpkin seed oil, plain yogurt, vinegar, salt, and pepper to make the dressing.", "After baking, add the potato quarters to the large bowl and toss with the dressing while still warm. Allow to marinate briefly.", "Gently fold in the mozzarella pieces and baby spinach. Season the potato salad with salt and pepper.", "Divide the warm potato salad into deep bowls, sprinkle with roasted pumpkin seeds, and enjoy."], "source": "hello_fresh_4.pdf"}, {"id": 26, "title": "GOAT CHEESE WITH ALMONDS ON LENTIL SALAD", "subtitle": "ready-to-eat dish with max. 20% carbohydrates", "title_de": "Ziegenkäse mit Mandeln auf Linsensalat", "prep_time_min": 40, "difficulty": 2, "protein_type": "vegetarian", "ingredients": [{"name_de": "braune Linsen", "name": "brown lentils", "quantity": "50", "unit": "g", "category": "pantry"}, {"name_de": "Rucola", "name": "arugula", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Ziegenfrischtäseler", "name": "fresh goat cheese rounds", "quantity": "1", "unit": "Stück", "category": "dairy & eggs"}, {"name_de": "Mandelblättchen", "name": "flaked almonds", "quantity": "20", "unit": "g", "category": "pantry"}, {"name_de": "Pfirsich-Ayvar-Dressing", "name": "peach ajvar dressing", "quantity": "35", "unit": "ml", "category": "pantry"}, {"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Kürbiskerne", "name": "pumpkin seeds", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Balsamico-Crème", "name": "balsamic glaze", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "getrocknete Cranberrys", "name": "dried cranberries", "quantity": "1", "unit": "Stück", "category": "pantry"}], "steps": ["Peel the sweet potato and cut into 1 cm cubes. Peel and finely slice the onion. In a large bowl, mix together vinegar, oil, mustard, salt, and pepper to make a dressing.", "In a large pan, toast the flaked almonds with a pinch of salt for approx. 3 min until lightly golden. Remove and set aside.", "Toast the seeds: Toast in a pan without any added fat and set aside to cool briefly.", "Spread the sweet potato cubes on a baking tray lined with parchment paper, drizzle with 1 tbsp oil and season with pepper. Roast at 200 °C for 20-25 min. Meanwhile, roll the goat cheese rounds in the flaked almonds to coat and pan-fry in a little oil for 2-3 min per side until golden.", "Add the rocket and lentils to the large bowl and carefully toss with the dressing. Season with salt and pepper.", "Divide the lentil salad onto plates. Top with the sweet potatoes and pan-fried goat cheese. Garnish with toasted seeds and the remaining flaked almonds."], "source": "hello_fresh_4.pdf"}, {"id": 27, "title": "BROCCOLI PATTIES WITH FETA DIP", "subtitle": "with oven sweet potatoes and romaine salad", "title_de": "Brokkolitaler mit Hirtenkäsedip", "prep_time_min": 45, "difficulty": 3, "protein_type": "vegetarian", "ingredients": [{"name_de": "Brokkoli", "name": "broccoli", "quantity": "250", "unit": "g", "category": "produce"}, {"name_de": "geriebener Hartkäse", "name": "grated hard cheese (parmesan-style)", "quantity": "1", "unit": "Stück", "category": "dairy & eggs"}, {"name_de": "Tomate", "name": "tomato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Joghurt", "name": "yogurt", "quantity": "75", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Petersilie", "name": "parsley", "quantity": "1", "unit": "Bund", "category": "produce"}, {"name_de": "Balsamico-Essig", "name": "balsamic vinegar", "quantity": "1", "unit": "EL", "category": "pantry"}, {"name_de": "Weizenmehl", "name": "wheat flour", "quantity": "1", "unit": "EL", "category": "pantry"}, {"name_de": "Salatherz (Romana)", "name": "romaine lettuce heart", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Hirtenkäse", "name": "feta-style cheese", "quantity": "150", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Frühlingszwiebel", "name": "spring onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Honig", "name": "honey", "quantity": "1", "unit": "TL", "category": "pantry"}], "steps": ["Preheat the oven to 200 °C top/bottom heat. Peel the sweet potato and cut into 1 cm thick rounds. Spread on a baking tray lined with parchment paper, drizzle with 1 tbsp [1.5 tbsp | 2 tbsp] oil, and season with salt and pepper. Roast for 20-25 min.", "Bring a large pot of salted water to the boil. Divide the broccoli into small florets and cook for 5-6 min until just tender. Drain and allow to cool slightly.", "Finely chop the broccoli florets. In a large bowl, mix together the broccoli, egg, breadcrumbs, grated cheese, garlic, salt, and pepper until a moldable mixture forms.", "Shape the mixture into small patties. Heat 1 tbsp [1.5 tbsp | 2 tbsp] oil in a large pan over medium heat and fry the patties for 3-4 min per side until golden brown.", "Make the feta dip: Crumble the feta into a bowl, add the yogurt, garlic, lemon juice, salt, and pepper, and stir until smooth.", "Plate up: Arrange the broccoli patties, oven sweet potato rounds, and romaine salad on plates. Serve with the feta dip."], "source": "hello_fresh_4.pdf"}, {"id": 28, "title": "ITALIAN ANTIPASTI BOWL", "subtitle": "with rice, zucchini, bell pepper, and mozzarella", "title_de": "Italienische Antipasti Bowl", "prep_time_min": 40, "difficulty": 3, "protein_type": "vegetarian", "ingredients": [{"name_de": "Risottoreis", "name": "risotto rice", "quantity": "200", "unit": "g", "category": "pantry"}, {"name_de": "Gewürzmischung Fette Buon Appetito", "name": "Buon Appetito spice mix", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Zucchini", "name": "zucchini", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Tomatenpesto", "name": "tomato pesto", "quantity": "50", "unit": "g", "category": "pantry"}, {"name_de": "Mozzarella", "name": "mozzarella", "quantity": "50", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Babyspinat", "name": "baby spinach", "quantity": "50", "unit": "g", "category": "produce"}, {"name_de": "Kirschtomaten", "name": "cherry tomatoes", "quantity": "100", "unit": "g", "category": "produce"}, {"name_de": "geriebener Hartkäse", "name": "grated hard cheese (parmesan-style)", "quantity": "7", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "gelbe Paprika", "name": "yellow bell pepper", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Schalotte", "name": "shallot", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Gemüsebrühe", "name": "vegetable stock", "quantity": "200", "unit": "ml", "category": "pantry"}, {"name_de": "Balsamico-Essig", "name": "balsamic vinegar", "quantity": "1", "unit": "EL", "category": "pantry"}], "steps": ["Trim the ends of the zucchini and bell pepper. Halve the bell pepper and remove the seeds, then cut into approx. 3-4 cm thick slices. Cut the zucchini into 1 cm thick rounds.", "In a large bowl, mix half the seasoning oil with olive oil, a little salt, and pepper. Toss the vegetables with the seasoning mix and spread on a baking tray lined with parchment paper. Roast at 200 °C for 20-25 min.", "Dissolve the vegetable stock powder in 600 ml hot water. In a large pot, heat 1 tbsp olive oil over medium heat. Add the rice and toast briefly. Pour in some of the broth and bring to a boil.", "Add a little broth to deglaze and continue cooking the rice, adding broth gradually, stirring in half the pesto. Cook until the rice is tender and the liquid has been absorbed.", "For the salad: Halve the cherry tomatoes and toss together with the dressing and baby spinach. Season to taste.", "Divide the rice into bowls or deep plates. Top with the antipasti vegetables and salad. Arrange the mozzarella on top and drizzle with the remaining pesto and seasoning oil."], "source": "hello_fresh_4.pdf"}, {"id": 29, "title": "GREEK MEZZE PLATTER", "subtitle": "with marinated feta, chickpeas, and hummus", "title_de": "Griechische Mezze-Platte", "prep_time_min": 40, "difficulty": 3, "protein_type": "vegetarian", "ingredients": [{"name_de": "Kichererbsen", "name": "chickpeas", "quantity": "380", "unit": "g", "category": "produce"}, {"name_de": "Hirtenkäse", "name": "feta-style cheese", "quantity": "150", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Tomate", "name": "tomato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Mini-Fladenbrot", "name": "mini flatbread", "quantity": "4", "unit": "Stück", "category": "pantry"}, {"name_de": "Gewürzmischung Hello Mezze", "name": "Hello Mezze spice mix", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "rote Paprika", "name": "red bell pepper", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Sahnejoghurt", "name": "creamy yogurt", "quantity": "100", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Oregano", "name": "oregano", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Gurke", "name": "cucumber", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Zitrone, gewachst", "name": "lemon", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Hummus", "name": "hummus", "quantity": "70", "unit": "g", "category": "pantry"}, {"name_de": "Petersilie", "name": "parsley", "quantity": "1", "unit": "Bund", "category": "produce"}], "steps": ["Cut the feta into approx. 1 cm cubes and marinate in 2 tbsp olive oil with half the spice blend.", "Drain the chickpeas in a sieve and rinse under running water. Spread on a baking tray lined with parchment paper, drizzle with 1 tbsp [1.5 tbsp | 2 tbsp] olive oil, the remaining spice blend, salt, and pepper. Roast at 200 °C for 20-25 min until crispy.", "Peel and halve the onion and cut into fine strips. Halve the tomato, remove the seeds, and cut into approx. 2 cm cubes. Cut the cucumber into cubes. Finely chop the parsley.", "Make the dressing: Cut the lemon into 4 wedges. In a large bowl, combine the cucumber, parsley, and dip. Squeeze in the juice of 1-2 lemon wedges and add olive oil, salt, and pepper. Stir to combine.", "Place the flatbread on the baking tray in the last 2-4 min of the chickpea cooking time and bake until crispy.", "Toss the hummus, chickpeas, and marinated feta cubes in the large bowl with the dressing. Divide onto plates and serve with the flatbread."], "source": "hello_fresh_4.pdf"}, {"id": 30, "title": "FLAMMKUCHEN WITH CAMEMBERT, HAZELNUTS, AND PEAR-LAMB'S LETTUCE", "subtitle": "with hazelnuts and pear-lamb's lettuce", "title_de": "Flammkuchen mit Camembert,", "prep_time_min": 40, "difficulty": 2, "protein_type": "vegetarian", "ingredients": [{"name_de": "frischer Flammkuchenteig", "name": "fresh tarte flambée dough", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Petersilie glatt/Thymian", "name": "flat-leaf parsley / thyme", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Creme fraiche", "name": "crème fraîche", "quantity": "150", "unit": "g", "category": "dairy & eggs"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Camembert", "name": "camembert", "quantity": "225", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Haselnüsse", "name": "hazelnuts", "quantity": "25", "unit": "g", "category": "pantry"}, {"name_de": "Senfsamen", "name": "mustard seeds", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Birne", "name": "pear", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Wildpreiselbeermarmelade", "name": "wild lingonberry jam", "quantity": "20", "unit": "g", "category": "pantry"}, {"name_de": "Rotweinessig", "name": "red wine vinegar", "quantity": "75", "unit": "ml", "category": "pantry"}, {"name_de": "Feldsalat", "name": "lamb's lettuce", "quantity": "1", "unit": "Stück", "category": "produce"}], "steps": ["Unroll the flammkuchen dough onto a baking tray lined with parchment paper and spread with the creme fraiche. Remove the leaves from the rosemary sprigs and sprinkle over the dough.", "Peel and halve the red onion and cut into fine strips. Cut the camembert into 0.5 cm thick slices. Arrange the onion strips and camembert slices on the flammkuchen. Season with salt and pepper.", "Bake the flammkuchen on the middle shelf for 15-18 min. Meanwhile, roughly chop the hazelnuts and continue with the recipe.", "In a large bowl, whisk together the wild cranberry jam, mustard seeds, vinegar, and 3 tbsp olive oil to make a dressing. Season with salt and pepper.", "Quarter the pear lengthwise, remove the core, and cut into thin slices. Add the salad and pear slices to the bowl and toss with the dressing.", "Remove the flammkuchen from the oven, cut into pieces, and allow to cool briefly. Arrange on plates. Top with the chopped hazelnuts, honey, and pear-lamb's lettuce salad."], "source": "hello_fresh_4.pdf"}, {"id": 31, "title": "INDIAN SWEET POTATO TIKKA CURRY", "subtitle": "with spinach, coconut milk, and chapati", "title_de": "Indisches Süßkartoffel-Tikka-Curry", "prep_time_min": 40, "difficulty": 2, "protein_type": "vegetarian", "ingredients": [{"name_de": "Babyspinat", "name": "baby spinach", "quantity": "75", "unit": "g", "category": "produce"}, {"name_de": "Chapati", "name": "chapati", "quantity": "4", "unit": "Stück", "category": "pantry"}, {"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Tikka-Masala-Paste", "name": "tikka masala paste", "quantity": "40", "unit": "g", "category": "pantry"}, {"name_de": "stückige Tomaten", "name": "diced tomatoes", "quantity": "250", "unit": "ml", "category": "produce"}, {"name_de": "Kokosmilch", "name": "coconut milk", "quantity": "250", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Joghurt", "name": "yogurt", "quantity": "75", "unit": "g", "category": "dairy & eggs"}], "steps": ["Peel the sweet potato and cut into 2 cm cubes. Peel and cut the red onion into eighths.", "Heat 1 tbsp oil in a large pot over high heat. Saute the onion wedges for approx. 1 min. Add the sweet potato cubes and cook for 3-4 min, stirring occasionally.", "Add the tikka paste and cook for approx. 1 min, stirring, until fragrant. Pour in the crushed tomatoes and coconut milk. Bring to a boil, then reduce heat and simmer for 15-20 min until the sweet potato is tender.", "Place the chapati bread on a baking tray lined with parchment paper and bake on the middle shelf for approx. 2 min until warmed through.", "Remove the curry from the heat, stir in the baby spinach, and allow to wilt (put the lid back on if needed). Season to taste with salt and pepper.", "Divide the sweet potato curry into bowls. Serve with yogurt and chapati bread."], "source": "hello_fresh_4.pdf"}, {"id": 32, "title": "HEARTY LENTIL BAKE", "subtitle": "with sweet potato, leek, and a cheesy topping", "title_de": "Herzhafter Linsenauflauf", "prep_time_min": 50, "difficulty": 3, "protein_type": "vegetarian", "ingredients": [{"name_de": "vorw. festk. Kartoffeln", "name": "waxy potatoes", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "braune Linsen", "name": "brown lentils", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "mittelsch. Senf", "name": "Dijon mustard", "quantity": "1", "unit": "EL", "category": "pantry"}, {"name_de": "Kochsahne", "name": "cooking cream", "quantity": "200", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Porree", "name": "leek", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Tomatensmark", "name": "tomato paste", "quantity": "10", "unit": "ml", "category": "pantry"}, {"name_de": "Käse-Mix", "name": "cheese blend", "quantity": "50", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "400", "unit": "g", "category": "produce"}, {"name_de": "Karotte", "name": "carrot", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Sojasoße", "name": "soy sauce", "quantity": "10", "unit": "ml", "category": "pantry"}, {"name_de": "Muskatnusspulver", "name": "ground nutmeg", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Zitrone, gewachst", "name": "lemon", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Kopfsalat", "name": "butterhead lettuce", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Sonnenblumenkerne", "name": "sunflower seeds", "quantity": "20", "unit": "g", "category": "pantry"}, {"name_de": "Gemüsebrühe", "name": "vegetable stock", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Honig", "name": "honey", "quantity": "1", "unit": "TL", "category": "pantry"}], "steps": ["Cut the leek diagonally into 1 cm thick slices. Peel and slice the carrot very thinly. Peel and dice the sweet potato and potato into 1-2 cm cubes. Preheat the oven to 200 °C top/bottom heat.", "Pour the cream into a tall mixing bowl and mix with half the vegetable stock powder, nutmeg, and pepper. Crumble in half the cheese mix and stir to combine.", "For the lentils: Heat 1 tbsp oil in a large pan. Add the diced shallot and garlic and saute for 1-2 min. Add the lentils and stir to coat. Pour in the broth and cook for 10-12 min until the lentils are just tender.", "Layer half the lentil mixture into a small baking dish. Top with half the vegetables and sprinkle over the cheese mix. Repeat the layering. Pour the cream mixture over the top. Bake at 200 °C for 25-30 min until golden.", "Tear the salad leaves and place in a small bowl. Whisk together the honey, 1 tbsp lemon juice, 1 tbsp olive oil, salt, and pepper to make a dressing.", "Remove the bake from the oven and let cool briefly. Add the sunflower seeds and toss with the dressing. Serve alongside."], "source": "hello_fresh_4.pdf"}, {"id": 33, "title": "TART WITH LEEK AND MUSHROOMS", "subtitle": "with a fresh cucumber-radish salad", "title_de": "Tarte mit Porree & Champignons,", "prep_time_min": 50, "difficulty": 2, "protein_type": "vegetarian", "ingredients": [{"name_de": "frischer Blätterteig", "name": "fresh puff pastry", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "mittelscharfer Senf", "name": "Dijon mustard", "quantity": "10", "unit": "ml", "category": "pantry"}, {"name_de": "Crème fraîche", "name": "crème fraîche", "quantity": "150", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Porree", "name": "leek", "quantity": "100", "unit": "g", "category": "produce"}, {"name_de": "Champignons", "name": "white mushrooms", "quantity": "200", "unit": "g", "category": "produce"}, {"name_de": "Käse-Mix", "name": "cheese blend", "quantity": "1", "unit": "Stück", "category": "dairy & eggs"}, {"name_de": "Radieschen", "name": "radishes", "quantity": "50", "unit": "g", "category": "produce"}, {"name_de": "Gurke", "name": "cucumber", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Honig", "name": "honey", "quantity": "8", "unit": "g", "category": "pantry"}, {"name_de": "Dill/Schnittlauch", "name": "dill / chives", "quantity": "15", "unit": "ml", "category": "produce"}, {"name_de": "süßer Senf", "name": "sweet mustard", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Haselnüsse", "name": "hazelnuts", "quantity": "1", "unit": "Stück", "category": "pantry"}], "steps": ["Unroll the puff pastry and place with the parchment paper on a baking tray. Spread with the mustard creme. Preheat the oven to 200 °C top/bottom heat.", "Halve the leek lengthwise and cut into 0.5 cm strips. Cut the mushrooms into 0.5 cm thick slices. Arrange the mushroom slices and leek strips on the pastry and bake for 20-25 min until golden and crispy.", "Thinly slice the radishes. Finely slice the dill or chives. Thinly slice the cucumber.", "Meanwhile, prepare the salad. For the dressing, in a large bowl, mix together the creme fraiche with half the sweet and sour dressing, salt, and pepper.", "Toast the hazelnuts in a small pan briefly. Allow to cool, then stir into the dressing.", "Remove the tart from the oven, cut into pieces, and allow to cool briefly. Arrange on plates and serve alongside the cucumber-radish salad."], "source": "hello_fresh_4.pdf"}, {"id": 34, "title": "ASIAN CHICKEN SKEWERS WITH HONEY", "subtitle": "with spicy chili-lime rice and grilled vegetables", "title_de": "Asiatische Hähnchenspiesse mit Honig,", "prep_time_min": 40, "difficulty": 3, "protein_type": "chicken", "ingredients": [{"name_de": "Limette, gewachst", "name": "lime", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "grüne Chilischote", "name": "green chili", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Ingwer", "name": "ginger", "quantity": "150", "unit": "g", "category": "produce"}, {"name_de": "Jasminreis", "name": "jasmine rice", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "Kokosmilch", "name": "coconut milk", "quantity": "250", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Hähnchenbrustsfilets", "name": "chicken breasts", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Sojasoße", "name": "soy sauce", "quantity": "50", "unit": "ml", "category": "pantry"}, {"name_de": "Holzspieße", "name": "wooden skewers", "quantity": "4", "unit": "Stück", "category": "other"}, {"name_de": "rote Spitzpaprika", "name": "red pointed pepper", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Frühlingszwiebeln", "name": "spring onions", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Honig", "name": "honey", "quantity": "30", "unit": "g", "category": "pantry"}], "steps": ["Grate the lime zest, then halve the lime, remove the seeds, and cut into wedges. Halve the chili and finely chop (caution: hot!). Finely grate the ginger.", "In a small pot, bring 150 ml water and the coconut milk to a boil. Add the lime zest, season with salt once, then stir in the rice. Reduce heat, cover, and cook for 10 min. Turn off the heat and allow to steam.", "Cut the chicken breast into approx. 2 cm pieces and add to a large bowl. Add the honey and ginger to the chicken. Thread the pieces onto skewers.", "Cut the pointed pepper into 1 cm thick rings. Cut the white part of the spring onion diagonally into 3-4 pieces. Spread on a baking tray lined with parchment paper, drizzle with 1 tbsp [1.5 tbsp | 2 tbsp] oil, season with salt and pepper. Roast at 200 °C for 15-20 min.", "Fry the skewers: Heat 1 tbsp oil in a large pan over medium heat. Fry the skewers for 8-10 min, turning, until cooked through. Remove from the pan.", "Remove the vegetables from the oven. Divide the rice onto plates. Arrange the skewers on the rice. Garnish with green spring onion rings, chili, and lime wedges."], "source": "hello_fresh_4.pdf"}, {"id": 35, "title": "ENCHILADAS WITH SMOKY TOMATO SAUCE", "subtitle": "with beans, spicy tomato salsa, and lime dip", "title_de": "Enchiladas mit rauchiger Tomatensoße,", "prep_time_min": 50, "difficulty": 3, "protein_type": "vegetarian", "ingredients": [{"name_de": "Tortilla-Wraps", "name": "tortilla wraps", "quantity": "4", "unit": "Stück", "category": "pantry"}, {"name_de": "Käse-Mix", "name": "cheese blend", "quantity": "50", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Paprika", "name": "bell pepper", "quantity": "70", "unit": "g", "category": "produce"}, {"name_de": "Tomatenmark", "name": "tomato paste", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Tomaten", "name": "tomatoes", "quantity": "150", "unit": "g", "category": "produce"}, {"name_de": "schwarze Bohnen", "name": "black beans", "quantity": "250", "unit": "g", "category": "pantry"}, {"name_de": "Schmand", "name": "sour cream", "quantity": "1", "unit": "Stück", "category": "dairy & eggs"}, {"name_de": "Frühlingszwiebel", "name": "spring onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Limette, gewachst", "name": "lime", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rauchiges Gewürz", "name": "smoky spice blend", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "grüne Chilischote", "name": "green chili", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Butter", "name": "butter", "quantity": "1", "unit": "Stück", "category": "dairy & eggs"}, {"name_de": "Gemüsebrühe", "name": "vegetable stock", "quantity": "100", "unit": "ml", "category": "pantry"}], "steps": ["Marinate the tomato salsa: Grate the lime zest. Squeeze one half into a small bowl and cut the other half into wedges. Halve the cherry tomatoes. Finely chop the coriander. In the small bowl, mix together the lime juice, tomatoes, coriander, and a pinch of sugar and salt. Set aside to marinate.", "Halve the bell pepper, remove the seeds, and cut into thin strips. Drain the black beans. Separate the white and green parts of the spring onion; slice into rings.", "Heat 1 tbsp oil in a large pan over medium heat. Add the garlic, white spring onion rings, and bell pepper strips and saute for 3-4 min. Add the black beans and season with the spice blend, salt, and pepper. Stir to combine.", "Fill the tortilla wraps with the bean mixture and roll up tightly. In the pan from step 3, add the butter, tomato sauce, and smoky seasoning over medium heat. Place the enchiladas seam-side down and pan-fry for 2-3 min. Transfer to a baking tray and sprinkle with grated cheese.", "Bake the enchiladas in the oven for 10-15 min until the cheese is golden. Meanwhile, stir together the remaining sour cream with lime zest and juice to make the lime dip.", "Divide the enchiladas onto plates. Drain the tomato salsa. Garnish the enchiladas with green spring onion rings and tomato salsa. Serve with the lime dip alongside."], "source": "hello_fresh_4.pdf"}, {"id": 36, "title": "SPICY OVEN HARISSA CHICKEN", "subtitle": "with sweet potato-chickpea vegetables and yogurt", "title_de": "Würziges Ofen-Harissa-Hähnchen", "prep_time_min": 40, "difficulty": 3, "protein_type": "chicken", "ingredients": [{"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Gewürzmischung Harissa", "name": "harissa spice mix", "quantity": "2", "unit": "g", "category": "pantry"}, {"name_de": "Hähnchenbrustsfilets", "name": "chicken breasts", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Kichererbsen", "name": "chickpeas", "quantity": "150", "unit": "g", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Petersilie", "name": "parsley", "quantity": "1", "unit": "Bund", "category": "produce"}, {"name_de": "Limette", "name": "lime", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Joghurt", "name": "yogurt", "quantity": "1", "unit": "Stück", "category": "dairy & eggs"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Ajvar", "name": "ajvar (red pepper spread)", "quantity": "25", "unit": "g", "category": "pantry"}], "steps": ["Peel the sweet potato and cut into 2-3 cm cubes. Spread on a baking tray lined with parchment paper. Drizzle with 1 tbsp [1.5 tbsp | 2 tbsp] oil, season with salt and pepper. Roast at 220 °C for 10 min.", "Press the garlic with the back of a knife until the skin loosens slightly. In a small bowl, mix together the spice blend, harissa, and 1 tbsp [1.5 tbsp | 2 tbsp] oil. Rub the chicken with the harissa oil and season with salt and pepper.", "Drain the chickpeas in a sieve and rinse with cold water. Add to the harissa oil marinade and toss to coat. Add to the sweet potato vegetables on the tray.", "Peel and halve the garlic, cut into wedges, and add to the baking tray 12 min before the end of cooking time. Score the skin of the chicken. Add the chicken to the tray and roast for a further 20-25 min until cooked through.", "In a small bowl, stir together the yogurt and ajvar. Season with a little salt and pepper. Halve the lime.", "Squeeze a little lime juice and scatter the chopped parsley over the vegetables. Divide the sweet potato-chickpea vegetables onto plates and arrange the chicken alongside. Serve with the ajvar yogurt."], "source": "hello_fresh_4.pdf"}, {"id": 37, "title": "HALLOUMI BURGER WITH CARROT-BEET STICKS", "subtitle": "with tomato and honey-mustard dressing", "title_de": "Halloumi-Burger mit Karotten-Bete-Sticks,", "prep_time_min": 40, "difficulty": 2, "protein_type": "vegetarian", "ingredients": [{"name_de": "frische Rote Bete", "name": "fresh beets", "quantity": "200", "unit": "g", "category": "produce"}, {"name_de": "Karotten", "name": "carrots", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Halloumi", "name": "halloumi", "quantity": "150", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Tomate", "name": "tomato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "mittelscharfer Senf", "name": "Dijon mustard", "quantity": "1", "unit": "EL", "category": "pantry"}, {"name_de": "Honig", "name": "honey", "quantity": "20", "unit": "g", "category": "pantry"}, {"name_de": "Salatblätter", "name": "salad leaves", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Crème fraîche", "name": "crème fraîche", "quantity": "20", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Brioche-Bun mit Sesam", "name": "brioche bun with sesame", "quantity": "1", "unit": "Stück", "category": "pantry"}], "steps": ["Peel the beets and carrots and cut into 1-2 cm thick sticks. Spread on a baking tray lined with parchment paper, drizzle with 1 tbsp [1.5 tbsp | 2 tbsp] oil, and season with salt and pepper. Roast at 200 °C for 20-25 min.", "Cut the halloumi into 2 cm thick slices. Trim and thinly slice the tomato. Peel and halve the red onion and cut into thin rings.", "In a small bowl, whisk together the mustard, honey, and creme fraiche to make a dressing. Season with salt and pepper.", "Place the burger buns in the oven for the last 3-5 min of the vegetable sticks cooking time and bake until golden.", "Heat 0.5 tbsp oil in a large pan over medium heat and fry the halloumi slices for approx. 5 min per side until golden. Fry the onion rings alongside until softened.", "Slice the buns open and place salad leaves on the bottom halves. Layer with mozzarella slices, tomato slices, halloumi, onion rings, and a drizzle of honey-mustard dressing. Close the burgers and serve alongside the carrot-beet sticks."], "source": "hello_fresh_4.pdf"}, {"id": 38, "title": "CHICKEN SOUVLAKI WITH OREGANO", "subtitle": "with tzatziki, mint wild rice, and Greek salad", "title_de": "Hähnchen-Souvlaki mit Oregano,", "prep_time_min": 50, "difficulty": 3, "protein_type": "chicken", "ingredients": [{"name_de": "Hähnchenbrustsfilets", "name": "chicken breasts", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Limette, gewachst", "name": "lime", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Oregano/Minze", "name": "oregano / mint", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Basmati-Wildreis-Mischung", "name": "basmati and wild rice blend", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "Knoblauchzehen", "name": "garlic cloves", "quantity": "2", "unit": "Stück", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "100", "unit": "g", "category": "produce"}, {"name_de": "Gurke", "name": "cucumber", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Sahnejoghurt", "name": "creamy yogurt", "quantity": "100", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Tomaten", "name": "tomatoes", "quantity": "100", "unit": "g", "category": "produce"}, {"name_de": "Holzspieße", "name": "wooden skewers", "quantity": "2", "unit": "Stück", "category": "other"}], "steps": ["Marinate the chicken: Cut the chicken breast into approx. 2 cm pieces. Juice the lime and add half to a large bowl. Add the oregano, olive oil, garlic, salt, and pepper. Add the chicken pieces, toss to coat, and thread onto skewers.", "Rinse the wild rice blend under cold water until the water runs clear. Peel and finely slice the garlic.", "Add the wild rice along with the hot water, a pinch of salt, garlic, and oregano stalks. Bring to a boil, then reduce heat and simmer with the lid on over low heat for 20-25 min.", "Make the tzatziki: Trim the ends of the cucumber and grate into a small bowl. Squeeze out excess moisture. Mix with the yogurt, remaining garlic, mint, olive oil, and lime juice. Season with salt and pepper.", "Fry the skewers: Heat 1 tbsp oil in a large pan. Fry the skewers on all sides for approx. 10 min until the chicken is cooked through and lightly charred.", "Divide the wild rice onto plates. Sprinkle the souvlaki skewers with the remaining oregano and serve alongside the tomato-cucumber salad and tzatziki."], "source": "hello_fresh_4.pdf"}, {"id": 39, "title": "CARIBBEAN SWEET POTATO COCONUT STEW", "subtitle": "with beans and hearty banana pancakes", "title_de": "Karibischer Süßkartoffel-Kokos-Eintopf", "prep_time_min": 50, "difficulty": 3, "protein_type": "vegetarian", "ingredients": [{"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "150", "unit": "g", "category": "produce"}, {"name_de": "Tomaten", "name": "tomatoes", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Spitzpaprika", "name": "red pointed pepper", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "schwarze Bohnen", "name": "black beans", "quantity": "250", "unit": "ml", "category": "pantry"}, {"name_de": "Gewürzmischung Südseetraum", "name": "South Sea Dream spice mix", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Kokosmilch", "name": "coconut milk", "quantity": "150", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Gemüsebrühe", "name": "vegetable stock", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Banane", "name": "banana", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Milch", "name": "milk", "quantity": "100", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Weizenmehl", "name": "wheat flour", "quantity": "75", "unit": "g", "category": "pantry"}, {"name_de": "rote Chilischote", "name": "red chili", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Backpulver", "name": "baking powder", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Petersilie", "name": "parsley", "quantity": "1", "unit": "Bund", "category": "produce"}], "steps": ["Prep the vegetables: Peel and finely dice the onion and garlic into 2 cm pieces. Peel and halve the sweet potato. Halve the tomatoes, remove the seeds, and dice. Deseed and dice the bell pepper.", "Heat 1 tbsp oil in a large pot. Saute the garlic for 3 min. Add the diced tomatoes and cook for another 3 min.", "Make the stew: Add the black beans, spice blend, sweet potato pieces, bell pepper pieces, and the coconut milk mixture to the pot. Bring to a boil and simmer for approx. 20 min until the sweet potato is tender.", "Make the pancake batter: Place the milk, flour, baking powder, and chopped parsley in a large bowl and mix everything together well. Stir in the mashed banana.", "Heat 1 tbsp oil in a large pan over medium heat. Working in batches, fry 4 pancakes from the batter, cooking each side for 3-4 min until golden brown.", "Divide the sweet potato coconut stew into deep bowls and scatter the remaining chopped parsley over the top. Arrange the banana pancakes alongside."], "source": "hello_fresh_4.pdf"}, {"id": 40, "title": "STUFFED CHICKEN BREAST IN BACON WRAP", "subtitle": "with diced potatoes and green beans", "title_de": "Gefüllte Hähnchenbrust im Baconmantel", "prep_time_min": 45, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "vorw. festk. Kartoffeln", "name": "waxy potatoes", "quantity": "600", "unit": "g", "category": "produce"}, {"name_de": "Rosmarinzweig", "name": "rosemary sprig", "quantity": "10", "unit": "ml", "category": "produce"}, {"name_de": "Frischkäse", "name": "cream cheese", "quantity": "200", "unit": "g", "category": "dairy & eggs"}, {"name_de": "mittelscharfer Senf", "name": "Dijon mustard", "quantity": "10", "unit": "ml", "category": "pantry"}, {"name_de": "Hähnchenbrustsfilets", "name": "chicken breasts", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Bacon", "name": "bacon", "quantity": "80", "unit": "g", "category": "meat & fish"}, {"name_de": "Buschbohnen", "name": "green beans", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}], "steps": ["Peel the potatoes and cut into approx. 2 cm cubes. Toss in a bowl with 1 tbsp oil and a little salt and pepper. Spread on a baking tray lined with parchment paper and roast at 200 °C for 20-25 min.", "Prepare the filling: Pick and chop the rosemary leaves. In a small bowl, mix together the cream cheese, mustard, rosemary, and a little salt and pepper.", "Cut a pocket into the side of each chicken breast and fill with the cream cheese mixture. Wrap each breast with 2 slices of bacon. In a large ovenproof pan, heat 1 tbsp oil over medium-high heat and sear the wrapped chicken for 2-3 min per side. Transfer to the oven and bake for 15-18 min until cooked through.", "Cook the beans: Trim the ends of the green beans. Bring a small pot of salted water to the boil and cook the beans for approx. 5 min until just tender. Drain and set aside.", "Peel and finely chop the garlic. In a small pot, prepare 100 ml chicken broth. Add the garlic and cook for approx. 5 min. Stir in the cream and remaining cream cheese and let reduce until slightly thickened. Season with salt and pepper.", "Divide the stuffed chicken breast, diced potatoes, and green beans onto plates. Drizzle with the cream cheese sauce."], "source": "hello_fresh_4.pdf"}, {"id": 41, "title": "ASIAN NOODLE PAN WITH LEMONGRASS", "subtitle": "with coconut milk, mushrooms, bell pepper, and ginger", "title_de": "Asia-Nudelpfanne mit Zitronengras,", "prep_time_min": 35, "difficulty": 2, "protein_type": "vegetarian", "ingredients": [{"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Frühlingszwiebeln", "name": "spring onions", "quantity": "150", "unit": "g", "category": "produce"}, {"name_de": "Paprika", "name": "bell pepper", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Champignons", "name": "white mushrooms", "quantity": "200", "unit": "g", "category": "produce"}, {"name_de": "Ingwer", "name": "ginger", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "Zitronengras", "name": "lemongrass", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Chilinudeln", "name": "chili noodles", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "Sesamöl", "name": "sesame oil", "quantity": "1", "unit": "EL", "category": "pantry"}, {"name_de": "Sojasoße", "name": "soy sauce", "quantity": "8", "unit": "ml", "category": "pantry"}, {"name_de": "Kokosmilch", "name": "coconut milk", "quantity": "250", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Honig", "name": "honey", "quantity": "20", "unit": "g", "category": "pantry"}, {"name_de": "rote Chilischote", "name": "red chili", "quantity": "1", "unit": "Stück", "category": "produce"}], "steps": ["Peel the garlic. Separate and finely slice the white and green parts of the spring onion. Halve the bell pepper, deseed, and cut into thin strips. Slice the mushrooms thinly. Finely grate the ginger. Bruise the lemongrass.", "Fill a large pot with plenty of boiling water, season generously with salt, and cook the noodles for approx. 5 min until tender. Drain through a sieve.", "Toast the sesame seeds in a large pan for 1-2 min until golden. Remove and set aside. In the same pan, heat the sesame oil, press in the garlic, add the white spring onion rings, ginger, and lemongrass, and saute for 1-2 min.", "Add the bell pepper strips and mushroom slices to the pan and saute. Add the soy sauce, coconut milk, and honey and cook briefly. Season with salt and pepper.", "Add the noodles to the vegetable pan, toss everything together, and season with salt and pepper. Remove the lemongrass from the pan.", "Divide the noodles onto plates. Sprinkle with toasted sesame seeds and green spring onion rings. Garnish with chopped chili to taste."], "source": "hello_fresh_4.pdf"}, {"id": 42, "title": "CREAMY SWEET POTATO STEW", "subtitle": "with bell pepper, spinach, and toasted flaked almonds", "title_de": "Cremiger Süßkartoffeleintopf", "prep_time_min": 40, "difficulty": 3, "protein_type": "vegetarian", "ingredients": [{"name_de": "mehligk. Kartoffeln", "name": "flour", "quantity": "3", "unit": "EL", "category": "pantry"}, {"name_de": "Paprika", "name": "bell pepper", "quantity": "50", "unit": "g", "category": "produce"}, {"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Babyspinat", "name": "baby spinach", "quantity": "100", "unit": "g", "category": "produce"}, {"name_de": "Tomatenmark", "name": "tomato paste", "quantity": "10", "unit": "ml", "category": "pantry"}, {"name_de": "Karotte", "name": "carrot", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Petersilie glatt/Thymian", "name": "flat-leaf parsley / thyme", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Butter", "name": "butter", "quantity": "10", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Gewürzmischung Paprikagewürz", "name": "paprika spice mix", "quantity": "8", "unit": "g", "category": "pantry"}, {"name_de": "Mandelblättchen", "name": "flaked almonds", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Schmand", "name": "sour cream", "quantity": "100", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Gemüsebrühe", "name": "vegetable stock", "quantity": "500", "unit": "ml", "category": "pantry"}, {"name_de": "Kürbiskernöl", "name": "pumpkin seed oil", "quantity": "10", "unit": "ml", "category": "pantry"}], "steps": ["Peel and finely slice the onions and sweet potatoes. Cut the potatoes into 1-2 cm cubes. Halve the bell pepper, deseed, and cut into strips. Peel and slice the carrots.", "Heat 1 tbsp oil in a large pot over medium heat. Add the onions, carrots, potatoes, and bell pepper and saute for 2-3 min. Add the garlic and cook for another minute.", "Pour in the prepared vegetable broth and add the thyme sprig. Season with salt and pepper and cook, covered, for approx. 20 min until all the vegetables are tender.", "Meanwhile, finely chop the parsley. Mix the sour cream with parsley, salt, and pepper. Toast the flaked almonds in a small pan without any fat until golden.", "At the end of the cooking time, remove the thyme. Add the spinach in small batches to the pot and stir until wilted. Stir in part of the cream and season again.", "Divide the sweet potato stew onto plates. Place a spoonful of the parsley sour cream in the center and sprinkle with the toasted flaked almonds."], "source": "hello_fresh_4.pdf"}, {"id": 43, "title": "CHICKEN STRIPS WITH SPAETZLE", "subtitle": "in a creamy apple and mushroom sauce", "title_de": "Hähnchengeschnetzeltes mit Spätzle", "prep_time_min": 40, "difficulty": 3, "protein_type": "chicken", "ingredients": [{"name_de": "Champignons", "name": "white mushrooms", "quantity": "150", "unit": "g", "category": "produce"}, {"name_de": "Petersilie glatt/Thymian", "name": "flat-leaf parsley / thyme", "quantity": "5", "unit": "g", "category": "produce"}, {"name_de": "Hähnchenbrustsfilets", "name": "chicken breasts", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Apfel", "name": "apple", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Kochsahne", "name": "cooking cream", "quantity": "200", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Eierspätzle", "name": "egg spätzle", "quantity": "400", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Butter", "name": "butter", "quantity": "10", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Thymian", "name": "thyme", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Spätzle", "name": "spätzle", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Gewürzmischung Hähnchen", "name": "chicken spice mix", "quantity": "3", "unit": "g", "category": "pantry"}], "steps": ["Slice the mushrooms into 0.5 cm thick pieces. Cut the apple halves into 0.5 cm thick slices as well. Pick the thyme leaves from the stalks. Finely chop the onion.", "Cut the chicken breast fillets into approx. 1 cm wide strips. Heat 1 tbsp oil in a large pan over medium heat. Season the chicken strips with salt and pepper and fry for 4-5 min until cooked through. Remove from the pan.", "Add the mushroom slices and cook for approx. 3 min. Then add the spice blend, thyme leaves, and apple slices and cook for another 2 min. Deglaze with the cooking cream and broth, and let reduce slightly.", "In a second large pan, heat 1 tbsp oil over medium heat and fry the spaetzle until golden brown. Add the butter and toss to coat.", "Pick and roughly chop the parsley leaves. Season the mushroom-apple sauce with salt and pepper.", "Divide the spaetzle and chicken strips onto plates and arrange in the mushroom-apple sauce. Garnish with the chopped parsley."], "source": "hello_fresh_4.pdf"}, {"id": 44, "title": "STIR FRY! SAUTEED VEGETABLES WITH PEANUT SAUCE", "subtitle": "with lime rice and peanuts", "title_de": "Stir Fry! Gebratenes Gemüse mit Erdnussoße,", "prep_time_min": 40, "difficulty": 1, "protein_type": "vegetarian", "ingredients": [{"name_de": "Jasminreis", "name": "jasmine rice", "quantity": "225", "unit": "g", "category": "pantry"}, {"name_de": "Buschbohnen", "name": "green beans", "quantity": "100", "unit": "g", "category": "pantry"}, {"name_de": "Paprika", "name": "bell pepper", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Champignons", "name": "white mushrooms", "quantity": "100", "unit": "g", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Ingwer", "name": "ginger", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "Frühlingszwiebeln", "name": "spring onions", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Sojasoße", "name": "soy sauce", "quantity": "30", "unit": "ml", "category": "pantry"}, {"name_de": "Kokosmilch", "name": "coconut milk", "quantity": "150", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Erdnussbutter", "name": "peanut butter", "quantity": "25", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Erdnüsse", "name": "peanuts", "quantity": "10", "unit": "g", "category": "pantry"}, {"name_de": "Karotten", "name": "carrots", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Limette, gewachst", "name": "lime", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Chilischote", "name": "red chili", "quantity": "1", "unit": "Stück", "category": "produce"}], "steps": ["Rinse the jasmine rice in a small sieve under cold water until the water runs clear. In a small pot, bring 450 ml water to a boil. Add the rice, reduce heat, cover, and cook for 10 min. Turn off the heat and let steam.", "Trim the ends of the green beans and halve them. Halve the bell pepper, deseed, and cut the halves into 1 cm strips. Peel and slice the carrots diagonally. Separate the white and green spring onion rings.", "Peel and finely chop the ginger. Peel and finely chop the garlic. Halve the chili, remove the seeds, and finely slice the halves (caution: hot!). Roughly chop the peanuts.", "Make the sauce: In a tall mixing bowl, combine the coconut milk, soy sauce, water, garlic, and ginger and mix well. Add the peanut butter and stir until smooth.", "Stir-fry the vegetables: Heat 1 tbsp oil in a large pan over high heat. Add the carrot, bell pepper, and white spring onion rings and stir-fry for 3-4 min. Add the beans and cook for another 2 min. Pour in the peanut sauce and cook for 2-3 min until the sauce has thickened.", "Fluff the jasmine rice with a fork, add the lime juice, and divide onto plates. Top with the stir-fried vegetables. Sprinkle with peanuts and green spring onion rings."], "source": "hello_fresh_4.pdf"}, {"id": 45, "title": "CHICKEN BURGER WITH MOZZARELLA", "subtitle": "with spicy onion relish and oven fries", "title_de": "Hänchenburger mit Mozzarella,", "prep_time_min": 50, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Kartoffeln", "name": "potatoes", "quantity": "400", "unit": "g", "category": "produce"}, {"name_de": "Gewürzmischung HelloMediterraneo", "name": "Hello Mediterraneo spice mix", "quantity": "2", "unit": "g", "category": "pantry"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "150", "unit": "g", "category": "produce"}, {"name_de": "Tomate", "name": "tomato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Saure Sahne", "name": "sour cream", "quantity": "250", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Mozzarella", "name": "mozzarella", "quantity": "1", "unit": "Stück", "category": "dairy & eggs"}, {"name_de": "Hähnchenbrustsfilets", "name": "chicken breasts", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Brioche-Buns mit Sesam", "name": "brioche buns with sesame", "quantity": "2", "unit": "Stück", "category": "pantry"}, {"name_de": "Salatblätter", "name": "salad leaves", "quantity": "1", "unit": "Stück", "category": "produce"}], "steps": ["Peel the potatoes and cut into approx. 1 cm thick batons. Spread the fries on a baking tray lined with parchment paper, drizzle with 1 tbsp [1.5 tbsp | 2 tbsp] oil, and season with salt and pepper. Bake at 200 °C for 25-30 min.", "Add the garlic to the tray for the last 10 min of baking. Peel and halve the red onion and cut into thin strips. In a small pan, heat a little oil and cook the onion strips with a pinch of sugar, salt, and vinegar for 8-10 min until caramelized.", "Meanwhile, halve the tomato, remove the core, and cut into 6 slices. Separate the lettuce leaves and wash.", "Season the chicken breast on both sides and fry in a large pan with 1 tbsp oil for approx. 5-6 min per side until no longer pink. Slice the chicken breast and place a slice of mozzarella on top. Cover briefly to melt the cheese.", "Assemble the burger: Slice the buns open. Place salad leaves, tomato slices, and onion rings on the bottom halves. Add the chicken with melted mozzarella and squeeze the roasted garlic over the top. Add the garlic dip.", "Divide the chicken burgers and fries onto plates and enjoy with the remaining garlic dip."], "source": "hello_fresh_4.pdf"}, {"id": 46, "title": "VEGETARIAN MASSAMAN CURRY", "subtitle": "with mini cauliflower, lentils, and sweet potato", "title_de": "VEGETARISCHES MASSAMAN-CURRY", "prep_time_min": 40, "difficulty": 2, "protein_type": "vegetarian", "ingredients": [{"name_de": "Kartoffeln", "name": "potatoes", "quantity": "2", "unit": "Stück", "category": "produce"}, {"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Mini-Blumenkohl", "name": "mini cauliflower", "quantity": "0.5", "unit": "Stück", "category": "produce"}, {"name_de": "Zucchini", "name": "zucchini", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "braune Linsen", "name": "brown lentils", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Massaman-Currypaste", "name": "massaman curry paste", "quantity": "20", "unit": "ml", "category": "pantry"}, {"name_de": "Kokosmilch", "name": "coconut milk", "quantity": "250", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Gemüsebrühe", "name": "vegetable stock", "quantity": "150", "unit": "ml", "category": "pantry"}, {"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Frühlingszwiebel", "name": "spring onion", "quantity": "1", "unit": "Stück", "category": "produce"}], "steps": ["Preheat the oven to 200 °C top/bottom heat. Peel the potatoes and sweet potato and cut both into 1 cm cubes. Divide the cauliflower into small florets. Cut the zucchini into pieces.", "Spread the potato cubes, cauliflower florets, zucchini pieces, and sweet potato cubes on a baking tray lined with parchment paper. Drizzle with 1 tbsp [1.5 tbsp | 2 tbsp] oil and season with salt and pepper. Roast for 25-30 min.", "Drain the lentils in a sieve and rinse until the water runs clear. Cook in 200 ml of the prepared vegetable broth for 10-12 min. Set aside.", "Heat 1 tbsp oil in a large pan. Add the onion strips and saute for 3-4 min until translucent. Add the curry paste to taste (careful: spicy!) and fry for 1 min.", "Add the coconut milk and lentils to the sauce in the pan and simmer for approx. 5 min until the sauce has thickened slightly. Add the roasted vegetables and stir to combine.", "Divide the curry onto plates, top with spring onions, and enjoy."], "source": "hello_fresh_7.pdf"}, {"id": 47, "title": "FETTUCCINE WITH CHICKEN AND OYSTER MUSHROOMS", "subtitle": "topped with hard cheese-garlic crumble", "title_de": "FETTUCCINE MIT HÄHNCHEN UND AUSTERNPILZEN", "prep_time_min": 40, "difficulty": 1, "protein_type": "chicken", "ingredients": [{"name_de": "Austernpilze", "name": "oyster mushrooms", "quantity": "100", "unit": "g", "category": "produce"}, {"name_de": "Hähnchenbrust", "name": "chicken breast", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Fettuccine", "name": "fettuccine", "quantity": "250", "unit": "g", "category": "pantry"}, {"name_de": "Kochsahne", "name": "cooking cream", "quantity": "200", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "geriebener Hartkäse", "name": "grated hard cheese (parmesan-style)", "quantity": "40", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "Semmelbrösele", "name": "breadcrumbs", "quantity": "25", "unit": "g", "category": "pantry"}, {"name_de": "Petersilie/Schnittlauch", "name": "parsley / chives", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "Hühnerbrühe", "name": "chicken stock", "quantity": "4", "unit": "g", "category": "pantry"}], "steps": ["Bring a large pot of plenty of water to the boil, salt it, and cook the fettuccine for approx. 12 min until al dente. Scoop out a measuring cup of pasta cooking water before draining and set aside.", "Tear the oyster mushrooms into approx. 1 cm wide strips toward the stem. Peel and finely chop the garlic. Cut the chicken breast crosswise into 1 cm strips. Season with salt and pepper.", "In a medium-large pan, heat 1 tbsp oil over medium heat. Add half the grated hard cheese, the breadcrumbs, and half the garlic. Toast, stirring constantly, for 2-3 min until golden. Remove the crumble and set aside.", "Heat the oil over high heat and fry the chicken breast and oyster mushrooms for 4-5 min until the chicken is lightly golden. Season with salt and pepper.", "Add the cooking cream and prepared chicken broth to the pan. Press the remaining garlic into the pan and stir everything together. Add some of the pasta cooking water and let reduce slightly.", "Drain the pasta after cooking and add to the pan. Divide the pasta onto plates. Top with the garlic-walnut crumble and the remaining hard cheese."], "source": "hello_fresh_7.pdf"}, {"id": 48, "title": "GNOCCHI IN CREAMY SPINACH-TOMATO SAUCE", "subtitle": "finished with aromatic chive-walnut oil", "title_de": "GNOCCHI IN CREMIGER SPINAT-TOMATEN-SOSSE", "prep_time_min": 40, "difficulty": 2, "protein_type": "vegetarian", "ingredients": [{"name_de": "frische Gnocchi", "name": "fresh gnocchi", "quantity": "400", "unit": "g", "category": "pantry"}, {"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "gelbe Paprika", "name": "yellow bell pepper", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "stückige Tomaten", "name": "diced tomatoes", "quantity": "75", "unit": "g", "category": "produce"}, {"name_de": "Basilikum/Petersilie", "name": "basil / parsley", "quantity": "20", "unit": "g", "category": "produce"}, {"name_de": "Babyspinat", "name": "baby spinach", "quantity": "100", "unit": "g", "category": "produce"}, {"name_de": "Walnüsse", "name": "walnuts", "quantity": "20", "unit": "g", "category": "pantry"}, {"name_de": "Schnittlauch", "name": "chives", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Crème fraîche", "name": "crème fraîche", "quantity": "75", "unit": "g", "category": "dairy & eggs"}], "steps": ["Peel and halve the garlic and cut into 0.5 cm cubes. Halve the bell pepper, remove the seeds, and cut into 1 cm cubes. Halve and finely dice the onion.", "Heat 1 tbsp oil in a large pot over medium heat and saute the onion-bell pepper cubes and garlic for 2-3 min. Add the crushed tomatoes and vegetable broth. Bring to a boil and simmer for 10-12 min. Season with salt and pepper.", "In a large pan, heat 1 tbsp oil over medium heat and fry the gnocchi for approx. 7-8 min until golden brown. Then add to the tomato sauce.", "Meanwhile, cut the chives into 0.5 cm rings. Roughly chop the walnuts. Combine both in a small bowl with the walnut oil and a pinch of salt.", "Stir the creme fraiche into the tomato sauce. Add the baby spinach and gnocchi in batches to the pot. Season the herbs with salt and pepper.", "Divide the gnocchi onto plates. Drizzle with the chive-walnut oil, garnish with the remaining basil leaves, and enjoy."], "source": "hello_fresh_7.pdf"}, {"id": 49, "title": "CHICKEN LEGS WITH HONEY BALSAMIC SAUCE", "subtitle": "with garlic green beans and sweet potato cubes", "title_de": "HÄHNCHENKEULEN MIT HONIG-BALSAMICO-SOSSE", "prep_time_min": 45, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Hähnchenkeulen", "name": "chicken thighs", "quantity": "500", "unit": "g", "category": "meat & fish"}, {"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "750", "unit": "g", "category": "produce"}, {"name_de": "Buschbohnen", "name": "green beans", "quantity": "300", "unit": "g", "category": "pantry"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "2", "unit": "Stück", "category": "produce"}, {"name_de": "Balsamicocreme", "name": "balsamic glaze", "quantity": "200", "unit": "g", "category": "pantry"}, {"name_de": "edelsüßes Paprikapulver", "name": "sweet paprika powder", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Tomate", "name": "tomato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Hühnerbrühe", "name": "chicken stock", "quantity": "12", "unit": "ml", "category": "pantry"}, {"name_de": "Butter", "name": "butter", "quantity": "20", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Honig", "name": "honey", "quantity": "1", "unit": "Stück", "category": "pantry"}], "steps": ["Preheat the oven to 220 °C top/bottom heat. Cut the unpeeled sweet potatoes into 1 cm cubes. Toss with 1 tbsp oil, salt, and pepper on a baking tray. Roast for 25-30 min until golden.", "Heat 1 tbsp oil in a large pan over medium heat. Rub the chicken legs with paprika powder. Brown the chicken legs for 3-4 min per side. Transfer to the baking tray with the sweet potatoes and roast in the oven for 20-25 min.", "Quarter the onion and tomato, remove the seeds from the tomato, and cut into 1 cm cubes. Peel and finely chop the garlic.", "Heat 1 tbsp oil in a large pot. Add the garlic and saute for 2 min. Rinse the green beans with cold water. Add the beans and cook for 5-7 min until just tender. Season with salt and pepper.", "Heat the large pan again without adding fat. Drain the balsamic glaze and fry for 3-4 min. Deglaze with the prepared broth. Add the onion, tomato, honey, and butter and let reduce into a sauce.", "Divide the sweet potato cubes and chicken legs onto deep plates. Spoon the honey balsamic sauce over the chicken and serve with the garlic green beans."], "source": "hello_fresh_7.pdf"}, {"id": 50, "title": "BABY SPINACH SPAETZLE PAN", "subtitle": "in creamy sauce with toasted walnuts", "title_de": "BABYSPINAT-SPÄTZLE-PFANNE", "prep_time_min": 40, "difficulty": 1, "protein_type": "vegetarian", "ingredients": [{"name_de": "Champignons", "name": "white mushrooms", "quantity": "200", "unit": "g", "category": "produce"}, {"name_de": "Spätzle", "name": "spätzle", "quantity": "400", "unit": "g", "category": "pantry"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Walnüsse", "name": "walnuts", "quantity": "30", "unit": "g", "category": "pantry"}, {"name_de": "Tomate", "name": "tomato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Chilischote", "name": "red chili", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Kochsahne", "name": "cooking cream", "quantity": "200", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Gemüsebrühe", "name": "vegetable stock", "quantity": "300", "unit": "ml", "category": "pantry"}, {"name_de": "BBQ-Pfeffermischung", "name": "BBQ pepper blend", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Babyspinat", "name": "baby spinach", "quantity": "100", "unit": "g", "category": "produce"}], "steps": ["Slice the mushrooms. Halve and finely dice the onion, removing the stem. Peel and finely chop the garlic. Dice the tomatoes.", "In a large pan, toast the walnuts over medium heat without any fat for 3-5 min. Remove the walnuts from the pan and set aside.", "In the same pan, heat 1 tbsp oil over medium heat and fry the spaetzle for approx. 5 min until crispy. Then remove from the pan. Add the mushrooms, onion, and garlic and saute for 3-4 min.", "Make the sauce: Stir the cooking cream and vegetable broth into the pan vegetables and let everything reduce for approx. 2 min until the sauce has thickened slightly.", "Add the spaetzle, diced tomatoes, and BBQ pepper blend and toss everything together. Add the spinach in small batches, turning, until wilted. Season with salt and pepper.", "Arrange the baby spinach spaetzle pan in deep bowls and sprinkle with the chopped walnuts."], "source": "hello_fresh_7.pdf"}, {"id": 51, "title": "CRUNCHY VEGETABLE PAN WITH FENNEL", "subtitle": "with fluffy coconut milk rice and cashew nuts", "title_de": "KNACKIGE GEMÜSEPFANNE MIT FENCHEL", "prep_time_min": 40, "difficulty": 1, "protein_type": "vegan", "ingredients": [{"name_de": "Jasminreis", "name": "jasmine rice", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "Kokosmilch", "name": "coconut milk", "quantity": "150", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "gelbe Paprika", "name": "yellow bell pepper", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Fenchelknolle", "name": "fennel bulb", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Zucchini", "name": "zucchini", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Ingwer", "name": "ginger", "quantity": "20", "unit": "g", "category": "produce"}, {"name_de": "Sweet-Chili-Soße", "name": "sweet chili sauce", "quantity": "40", "unit": "ml", "category": "pantry"}, {"name_de": "Sojasoße", "name": "soy sauce", "quantity": "40", "unit": "ml", "category": "pantry"}, {"name_de": "Honig", "name": "honey", "quantity": "10", "unit": "g", "category": "pantry"}, {"name_de": "Thai-Basilikum", "name": "Thai basil", "quantity": "20", "unit": "g", "category": "produce"}, {"name_de": "Cashewkerne", "name": "cashews", "quantity": "20", "unit": "g", "category": "pantry"}], "steps": ["Rinse the jasmine rice in a sieve under cold water until it runs clear. In a small pot, combine 150 ml water and the coconut milk, bring to a boil. Stir in the rice, reduce heat, cover, and cook for 10 min. Turn off the heat and let steam.", "Peel and slice the garlic. Halve the onion, remove the seeds from the bell pepper halves, and roughly dice. Trim and slice the fennel into thin wedges. Dice the zucchini.", "Peel and finely grate the ginger. Press the garlic into a small bowl. Add the soy sauce, sweet chili sauce, honey, and 2 tbsp water and mix well.", "Heat 1 tbsp oil in a large pan over medium heat. Add the onion wedges, bell pepper pieces, and zucchini pieces and saute for 3-4 min. Add the fennel and cashews and cook for another 2-3 min.", "Meanwhile, pick and roughly chop the Thai basil. Add half the chopped Thai basil to the vegetables in the pan. Pour in the sauce and toss everything together.", "Fluff the basmati rice after steaming and divide onto plates. Top with the vegetable pan and garnish with the remaining chives and Thai basil."], "source": "hello_fresh_7.pdf"}, {"id": 52, "title": "MEXICAN OVEN-BAKED SWEET POTATOES", "subtitle": "with guacamole and creamy sour cream dip", "title_de": "MEXIKANISCHE SÜSSKARTOFFEL AUS DEM OFEN", "prep_time_min": 50, "difficulty": 1, "protein_type": "vegetarian", "ingredients": [{"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "2", "unit": "Stück", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Kidneybohnen", "name": "kidney beans", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Gewürzmischung \"HelloMexico\"", "name": "Hello Mexico spice mix", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Frühlingszwiebel", "name": "spring onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Mais", "name": "corn", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Tomate", "name": "tomato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Avocado", "name": "avocado", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Limette (gewachst)", "name": "lime", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Koriander/Petersilie glatt", "name": "cilantro / flat-leaf parsley", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "saure Sahne", "name": "sour cream", "quantity": "75", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Käse-Mix", "name": "cheese blend", "quantity": "50", "unit": "g", "category": "dairy & eggs"}, {"name_de": "rote Chilischote", "name": "red chili", "quantity": "1", "unit": "Stück", "category": "produce"}], "steps": ["Preheat the oven to 200 °C top/bottom heat. Halve the unpeeled sweet potatoes lengthwise and carefully prick the cut sides multiple times with a fork. Place cut-side down on a baking tray and bake for 30-35 min.", "Halve the chili, remove the seeds, and cut into thin strips (caution: hot!). Separate the white and green parts of the spring onion and slice into rings. Finely dice the tomato.", "Wash the lime in hot water. Grate the lime zest into a small bowl and squeeze in the juice. Add the sour cream and stir to combine. Season with salt.", "Make the tomato salsa: Halve the tomatoes, remove the core, and cut into approx. 1-2 cm cubes. Add to a bowl with the white spring onion rings, a little lime juice, coriander, sugar, salt, and pepper. Mix well.", "Heat a pan over medium heat with 1 tbsp oil. Fry the white spring onion rings for 1 min. Add the spice blend. Add the kidney beans and cook for 2-3 min. Season with salt and pepper.", "After baking, flip the sweet potato halves, spread 1 tbsp butter over each, and mash the insides with a fork. Spoon the bean mixture and guacamole on top. Serve with the tomato salsa and lime sour cream dip."], "source": "hello_fresh_7.pdf"}, {"id": 53, "title": "HAKE ON CREAMY LEEK VEGETABLES", "subtitle": "with spiced lentils", "title_de": "SEEHECHT AUF CREMIGEM PORREEGEMÜSE", "prep_time_min": 35, "difficulty": 2, "protein_type": "fish", "ingredients": [{"name_de": "Karotte", "name": "carrot", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Selleriesange", "name": "celery stalk", "quantity": "0.5", "unit": "Stück", "category": "produce"}, {"name_de": "Porree", "name": "leek", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Chilischote", "name": "red chili", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Salbei/Thymian", "name": "sage / thyme", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "braune Linsen", "name": "brown lentils", "quantity": "150", "unit": "g", "category": "pantry"}, {"name_de": "Seehecht", "name": "hake", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Crème fraîche", "name": "crème fraîche", "quantity": "225", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Hühnerbrühe", "name": "chicken stock", "quantity": "375", "unit": "ml", "category": "pantry"}], "steps": ["Preheat the oven to 200 °C top/bottom heat. Cut the carrot and celery stalk into small cubes. Slice the leek into 0.5 cm rings. Finely chop the chili.", "Pick the thyme and sage leaves from their stalks and roughly chop both.", "Heat 1 tbsp oil in a large pan over medium heat. Add the carrot and celery cubes, leek rings, and chili rings (caution: hot!) and saute for 3-4 min. Add the thyme and sage and stir.", "Meanwhile, season the hake fillets with salt, pepper, and oil. Place the hake on a baking tray lined with parchment paper and bake in the oven for 12-15 min until cooked through.", "Rinse the lentils in a sieve under cold water until it runs clear. Add 4 tbsp water and chicken broth to the vegetables. Stir in the lentils and cooking cream and let everything simmer for 5-7 min. Season with salt and pepper.", "Divide the creamy leek vegetables onto plates and arrange the hake on top. Enjoy."], "source": "hello_fresh_7.pdf"}, {"id": 54, "title": "CHICKEN BREAST ON GREEK SALAD", "subtitle": "with feta and crispy flatbread croutons", "title_de": "HÄHNCHENBRUST AUF GRIECHISCHEM SALAT", "prep_time_min": 35, "difficulty": 1, "protein_type": "chicken", "ingredients": [{"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "geriebener Oregano", "name": "dried oregano", "quantity": "2", "unit": "g", "category": "pantry"}, {"name_de": "Hähnchenbrustilets", "name": "chicken breasts", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Mini-Fladenbrot", "name": "mini flatbread", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Tomaten", "name": "tomatoes", "quantity": "3", "unit": "Stück", "category": "produce"}, {"name_de": "Gurke", "name": "cucumber", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Minze/Petersilie", "name": "mint / parsley", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "Zitrone, gewachst", "name": "lemon", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Hirtenkäse", "name": "feta-style cheese", "quantity": "100", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Rotweinessig", "name": "red wine vinegar", "quantity": "12", "unit": "ml", "category": "pantry"}], "steps": ["Peel, halve, and very finely slice the onion. In a large bowl, combine with the oregano, vinegar, and 3 tbsp olive oil. Season with salt and pepper and set aside to marinate.", "Cut the chicken breast into approx. 1 cm wide strips. Peel and press the garlic. Mix the chicken with a little salt and pepper, the garlic, and olive oil to marinate.", "Cut the flatbread into approx. 2 cm cubes. Heat 0.5 tbsp oil in a large pan, add the flatbread cubes, and toast for approx. 5 min until crispy. Season with salt and set aside.", "Heat the large pan again over high heat without adding fat. Fry the chicken strips for 6-7 min, turning, until cooked through and lightly charred.", "Add the cucumber cubes, tomato quarters, flatbread croutons, and chopped herbs to the onion strips in the bowl. Toss everything together.", "Roughly crumble the feta with your hands and fold into the salad. Divide the Greek salad onto plates and top with the chicken strips."], "source": "hello_fresh_8.pdf"}, {"id": 55, "title": "LEMONY FISH FILLET", "subtitle": "with potato salad with cucumber and radishes", "title_de": "ZITRONIGES FISCHFILET", "prep_time_min": 40, "difficulty": 1, "protein_type": "fish", "ingredients": [{"name_de": "Seehecht", "name": "hake", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Gurke", "name": "cucumber", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Schnittlauch", "name": "chives", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "Frühlingszwiebel", "name": "spring onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Zitrone, gewachst", "name": "lemon", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "mittelscharfer Senf", "name": "Dijon mustard", "quantity": "10", "unit": "ml", "category": "pantry"}, {"name_de": "Radieschen", "name": "radishes", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "vorw. festk. Kartoffeln", "name": "waxy potatoes", "quantity": "500", "unit": "g", "category": "produce"}, {"name_de": "Schmand", "name": "sour cream", "quantity": "100", "unit": "g", "category": "dairy & eggs"}], "steps": ["Peel, halve, and slice the potatoes into 1 cm wide pieces. Boil plenty of water in a kettle, salt it, and cook the potatoes for 12-15 min until tender.", "Trim the ends of the cucumber, halve it, remove the seeds with a spoon, and cut into 0.5 cm half-moons. Thinly slice the radishes. Finely slice the spring onions.", "In a large bowl, whisk together the sour cream, mustard, lemon wedge juice, a dash of olive oil, salt, and pepper to make a dressing.", "Drain the potatoes using the lid, allow to cool slightly, and fold into the dressing.", "Season the hake fillets with salt. Heat 2 tbsp oil in a large pan over medium heat and fry the hake fillets for 5-7 min until cooked through and lightly golden.", "Divide the potato salad onto plates, place the fish on top, and garnish with green spring onion rings. Enjoy."], "source": "hello_fresh_8.pdf"}, {"id": 56, "title": "CAESAR SALAD WITH PAN-FRIED GNOCCHI", "subtitle": "with marinated, baked cherry tomatoes", "title_de": "CAESAR-SALAT MIT GEBRATENEN GNOCCHI", "prep_time_min": 40, "difficulty": 2, "protein_type": "vegetarian", "ingredients": [{"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Mayonnaise", "name": "mayonnaise", "quantity": "34", "unit": "ml", "category": "pantry"}, {"name_de": "Hartkäse geraspelt", "name": "grated hard cheese", "quantity": "40", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Joghurt", "name": "yogurt", "quantity": "100", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Salatherz", "name": "lettuce heart", "quantity": "200", "unit": "g", "category": "produce"}, {"name_de": "Kirschtomaten", "name": "cherry tomatoes", "quantity": "300", "unit": "g", "category": "produce"}, {"name_de": "Worcester Sauce", "name": "Worcestershire sauce", "quantity": "4", "unit": "ml", "category": "pantry"}, {"name_de": "frische Gnocchi", "name": "fresh gnocchi", "quantity": "400", "unit": "g", "category": "pantry"}, {"name_de": "Schnittlauch", "name": "chives", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "Rotweinessig", "name": "red wine vinegar", "quantity": "12", "unit": "ml", "category": "pantry"}], "steps": ["Preheat the oven to 220 °C fan. Place the cherry tomatoes in a large bowl, press in half the garlic, drizzle with olive oil, and season with salt and pepper. Toss to coat.", "Spread the cherry tomatoes on a baking tray lined with parchment paper and bake in the oven for 15 min until they burst and are slightly caramelized.", "Heat 1 tbsp oil in a large pan over medium heat. Fry the gnocchi for 5-8 min, stirring occasionally, until golden and crispy on all sides.", "In a tall mixing bowl, blend half the grated cheese, mayonnaise, yogurt, Worcestershire sauce, and red wine vinegar with a hand blender until smooth. Season with salt and pepper.", "Halve the lettuce heart, cut lengthwise into wide strips, and place in the large bowl. Drizzle with the dressing and toss to coat. Slice the chives and add to the salad.", "Arrange the salad in bowls and top with the cherry tomatoes. For extra flavour, drizzle a little of the tomato roasting juices over the top. Add the crispy gnocchi and sprinkle with the remaining grated cheese."], "source": "hello_fresh_8.pdf"}, {"id": 57, "title": "CARIBBEAN SWEET POTATO COCONUT STEW WITH BANANA PANCAKES", "subtitle": "with beans and hearty banana pancakes", "title_de": "KARIBISCHER SÜSSKARTOFFEL-KOKOS-EINTOPF", "prep_time_min": 50, "difficulty": 3, "protein_type": "vegan", "ingredients": [{"name_de": "Banane", "name": "banana", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Petersilie", "name": "parsley", "quantity": "10", "unit": "g", "category": "produce"}, {"name_de": "rote Chilischote", "name": "red chili", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Milch", "name": "milk", "quantity": "100", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "schwarze Bohnen", "name": "black beans", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Gewürzmischung \"Hello Aloha\"", "name": "Hello Aloha spice mix", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Tomate", "name": "tomato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Gemüsebrühe", "name": "vegetable stock", "quantity": "150", "unit": "ml", "category": "pantry"}, {"name_de": "Kokosmilch", "name": "coconut milk", "quantity": "100", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Weizenmehl", "name": "wheat flour", "quantity": "75", "unit": "g", "category": "pantry"}, {"name_de": "Backpulver", "name": "baking powder", "quantity": "2", "unit": "g", "category": "pantry"}, {"name_de": "rote Spitzpaprika", "name": "red pointed pepper", "quantity": "1", "unit": "Stück", "category": "produce"}], "steps": ["Peel and finely dice the onion and garlic into 2 cm cubes. Peel the sweet potato and halve the tomatoes, remove the core, and dice. Deseed and dice the bell pepper.", "Heat 1 tbsp oil in a large pot over medium heat. Saute the onion and garlic cubes for 3 min. Add the diced tomatoes and cook for another 3 min.", "Add the black beans, spice blend, sweet potato cubes, coconut milk mixture, and sauce to the pot. Bring to a boil and simmer for approx. 20 min until the sweet potato is tender.", "Pick and finely chop the parsley leaves. Halve the chili, deseed, and finely chop the halves. In a large bowl, combine the milk, flour, baking powder, parsley, and mashed banana. Mix until smooth.", "Heat 1 tbsp oil in a large pan over medium heat. Working in batches, fry 4 pancakes from the batter for approx. 5 min per side until golden brown.", "Divide the sweet potato coconut stew into deep bowls and scatter the remaining parsley over the top. Arrange the banana pancakes alongside."], "source": "hello_fresh_8.pdf"}, {"id": 58, "title": "CHICKEN BREAST WITH BACON", "subtitle": "oven-roasted carrots and peppercorn cream sauce", "title_de": "HÄHNCHENBRUST MIT BACON", "prep_time_min": 50, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Hähnchenbrustilet", "name": "chicken breast", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Bacon", "name": "bacon", "quantity": "100", "unit": "g", "category": "meat & fish"}, {"name_de": "mittelscharfer Senf", "name": "Dijon mustard", "quantity": "10", "unit": "ml", "category": "pantry"}, {"name_de": "Hühnerbrühe", "name": "chicken stock", "quantity": "20", "unit": "ml", "category": "pantry"}, {"name_de": "Karotte", "name": "carrot", "quantity": "4", "unit": "Stück", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "2", "unit": "Stück", "category": "produce"}, {"name_de": "Kartoffeln (Drillinge)", "name": "baby potatoes", "quantity": "300", "unit": "g", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Kochsahne", "name": "cooking cream", "quantity": "200", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Kampot Pfeffer", "name": "Kampot pepper", "quantity": "2", "unit": "g", "category": "pantry"}, {"name_de": "lila Karotte", "name": "purple carrot", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Hühnerfrühe", "name": "chicken stock", "quantity": "1", "unit": "Stück", "category": "pantry"}], "steps": ["Preheat the oven to 200 °C fan. Peel the orange and purple carrots, halve crosswise, and cut the halves into 1 cm thick wedges lengthwise.", "Spread the vegetables on a baking tray lined with parchment paper, toss with 1 tbsp oil and a pinch each of salt and pepper. Roast for 25-30 min.", "Spread the chicken breasts with mustard and wrap each with 2 slices of bacon.", "Heat 1 tbsp oil in a large pan. Sear the bacon-wrapped chicken on all sides for 2-3 min. Add to the baking tray with the vegetables and roast for 15-18 min until cooked through.", "Reheat the pan, add the onion and press in the garlic. Saute for 2 min until translucent. Deglaze with the cream, add the green peppercorns and broth, and let reduce for 3-4 min into a sauce. Season with salt.", "Arrange the oven vegetables, chicken breast, and sauce on plates and enjoy."], "source": "hello_fresh_8.pdf"}, {"id": 59, "title": "ENCHILADAS WITH SMOKY TOMATO SAUCE AND LIME DIP", "subtitle": "with beans, spicy tomato salsa, and lime dip", "title_de": "ENCHILADAS MIT RAUCHIGER TOMATENSOSSE", "prep_time_min": 50, "difficulty": 2, "protein_type": "vegetarian", "ingredients": [{"name_de": "Tortilla-Wraps", "name": "tortilla wraps", "quantity": "4", "unit": "Stück", "category": "pantry"}, {"name_de": "Käse-Mix", "name": "cheese blend", "quantity": "50", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Tomatenmark", "name": "tomato paste", "quantity": "2", "unit": "EL", "category": "pantry"}, {"name_de": "gelbe Paprika", "name": "yellow bell pepper", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Limette, gewachst", "name": "lime", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Schmand", "name": "sour cream", "quantity": "150", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Frühlingszwiebel", "name": "spring onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "grüne Chilischote", "name": "green chili", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Tomate", "name": "tomato", "quantity": "2", "unit": "Stück", "category": "produce"}, {"name_de": "schwarze Bohnen", "name": "black beans", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "Butter", "name": "butter", "quantity": "1", "unit": "EL", "category": "dairy & eggs"}, {"name_de": "rauchiges Gewürz", "name": "smoky spice blend", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "Gemüsebrühe", "name": "vegetable stock", "quantity": "150", "unit": "ml", "category": "pantry"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}], "steps": ["Wash the lime in hot water and grate the zest. Cut one half into wedges and squeeze the other half. Halve the chili, deseed, and finely chop the halves (caution: hot!). Mix together the cherry tomatoes, coriander, lime juice, chili, and a pinch of salt and sugar for the salsa. Set aside.", "Halve the bell pepper, remove the seeds, and cut into thin strips. Separate the white and green parts of the spring onion and slice into rings.", "Heat 1 tbsp oil in a large pan over medium heat. Add the garlic, bell pepper, and white spring onion rings and saute for 3-4 min. Add the black beans and season with the spice blend, salt, and pepper.", "Fill the tortilla wraps with the bean mixture and roll up. In the same pan, heat butter over medium heat. Add the tomato sauce and smoky seasoning. Place the enchiladas seam-side down and pan-fry briefly. Transfer to a small baking dish.", "Spread the remaining tomato sauce over the wraps and scatter over the grated cheese. Bake the enchiladas in the oven for 10-15 min until the cheese is golden and bubbling.", "Drain the tomato salsa if desired. Top the enchiladas with green spring onion rings and divide onto plates. Serve with the sour cream lime dip alongside."], "source": "hello_fresh_8.pdf"}, {"id": 60, "title": "CHILI SWEET POTATO KUMPIR", "subtitle": "with roasted vegetables and creamy sour cream dip", "title_de": "CHILI-SÜSSKARTOFFEL-KUMPIR", "prep_time_min": 45, "difficulty": 1, "protein_type": "vegetarian", "ingredients": [{"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "2", "unit": "Stück", "category": "produce"}, {"name_de": "stückige Tomaten", "name": "diced tomatoes", "quantity": "150", "unit": "g", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Kidneybohnen", "name": "kidney beans", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "gelbe Paprika", "name": "yellow bell pepper", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Zwiebel", "name": "red onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Gewürzmischung \"HelloMexico\"", "name": "Hello Mexico spice mix", "quantity": "4", "unit": "g", "category": "pantry"}, {"name_de": "rauchiges Gewürz", "name": "smoky spice blend", "quantity": "2", "unit": "g", "category": "pantry"}, {"name_de": "Kirschtomaten", "name": "cherry tomatoes", "quantity": "200", "unit": "g", "category": "produce"}, {"name_de": "Käse-Mix", "name": "cheese blend", "quantity": "50", "unit": "g", "category": "dairy & eggs"}, {"name_de": "saure Sahne", "name": "sour cream", "quantity": "150", "unit": "g", "category": "dairy & eggs"}, {"name_de": "rote Chilischote", "name": "red chili", "quantity": "1", "unit": "Stück", "category": "produce"}], "steps": ["Preheat the oven to 200 °C fan. Halve the unpeeled sweet potatoes lengthwise and prick the cut sides carefully multiple times with a fork. Place cut-side down on a baking tray and bake for 35-40 min.", "Halve the yellow bell pepper, deseed, and cut the halves into 1 cm wide strips. Peel and halve the onion; cut one half into rings and finely dice the other half. Halve the cherry tomatoes.", "Add the onion rings and bell pepper strips to the sweet potatoes on the tray for the last 15 min of baking. Remove the cherry tomatoes when done.", "Heat 1 tbsp oil in a large pan over medium heat. Add the diced onion and saute for 1 min. Add the crushed tomatoes and chopped chili. Stir in the spice blend and season with salt and pepper. Simmer for 8-10 min.", "Drain the kidney beans through a sieve until the water runs clear. Add to the chili 5 min before the end of cooking time. Season with salt and pepper.", "After baking, flip the sweet potato halves, spread 1 tbsp butter and the cheese mix over each, and mash the insides with a fork. Spoon the chili into the sweet potato halves. Serve with the sour cream dip, roasted bell pepper, and onion on the side."], "source": "hello_fresh_8.pdf"}, {"id": 61, "title": "TIKKA MASALA CURRY WITH CHICKEN BREAST", "subtitle": "with chickpeas and sweet potato", "title_de": "TIKKA-MASALA-CURRY MIT HÄHNCHENBRUST", "prep_time_min": 40, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Kichererbsen", "name": "chickpeas", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Kokosmilch", "name": "coconut milk", "quantity": "250", "unit": "ml", "category": "dairy & eggs"}, {"name_de": "Zwiebel", "name": "onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Tikka-Masala-Paste", "name": "tikka masala paste", "quantity": "20", "unit": "g", "category": "pantry"}, {"name_de": "Hähnchenbrustilet", "name": "chicken breast", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Kartoffeln", "name": "potatoes", "quantity": "2", "unit": "Stück", "category": "produce"}, {"name_de": "Frühlingszwiebel", "name": "spring onion", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Zucchini", "name": "zucchini", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Gemüsebrühe", "name": "vegetable stock", "quantity": "4", "unit": "g", "category": "pantry"}], "steps": ["Preheat the oven to 200 °C fan. Peel the sweet potatoes and potatoes and cut into 1 cm cubes. Trim the ends of the zucchini and cut into pieces. Halve and slice the onion into strips.", "Spread the zucchini pieces, potato, and sweet potato cubes on a baking tray lined with parchment paper. Drizzle with 1 tbsp olive oil and season with salt and pepper. Roast for 25-30 min.", "Drain the chickpeas in a sieve and rinse with hot water. Prepare 100 ml vegetable broth. Cut the chicken breast into 1 cm strips.", "Heat 1 tbsp oil in a large pan. Add the chicken and onion strips and saute for 3-4 min. Add the tikka masala paste and cook for 1 min, stirring, until fragrant.", "Add the coconut milk and chickpeas to the sauce in the pan and simmer for approx. 5-7 min until the sauce reaches the desired consistency. Stir in the roasted vegetables.", "Divide the curry into deep bowls, top with spring onion rings, and enjoy."], "source": "hello_fresh_8.pdf"}, {"id": 62, "title": "CHICKEN BREAST FILLETS WITH SPICY BROCCOLINI", "subtitle": "with creamy sweet potato-carrot puree", "title_de": "HÄHNCHENBRUSTFILETS MIT SCHARFEM BROKKOLINI", "prep_time_min": 40, "difficulty": 1, "protein_type": "chicken", "ingredients": [{"name_de": "Hähnchenbrustilets", "name": "chicken breasts", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Brokkolini", "name": "broccolini", "quantity": "150", "unit": "g", "category": "produce"}, {"name_de": "Karotten", "name": "carrots", "quantity": "3", "unit": "Stück", "category": "produce"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "rote Chilischote", "name": "red chili", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Schmand", "name": "sour cream", "quantity": "200", "unit": "g", "category": "dairy & eggs"}, {"name_de": "Süßkartoffel", "name": "sweet potato", "quantity": "1", "unit": "Stück", "category": "produce"}], "steps": ["Preheat the oven to 200 °C top/bottom heat. Boil plenty of water in a kettle. Peel the sweet potato and carrots and cut into even pieces.", "Cook the sweet potato pieces for 10-12 min and the carrot pieces until soft as well. After cooking, drain the sweet potato and carrot through a sieve, reserving a little cooking water.", "Meanwhile, trim the ends of the broccolini. Peel and finely chop the garlic. Halve the chili lengthwise (caution: hot!) and cut into thin rings.", "Season the chicken breast fillets with salt and pepper. Heat 1 tbsp oil in a large pan, sear the fillets on high heat, then transfer to a baking tray and bake in the oven for 12-15 min until cooked through.", "Heat 1 tbsp oil again in the pan. Saute the chopped garlic and chili rings (caution: hot!). Add 100 ml water and the broccolini and cook for 3-4 min until just tender. Season with salt and soy sauce.", "Remove the cooked chicken breast fillets from the oven and slice. Divide the sweet potato-carrot puree onto plates and arrange the chicken and spicy broccolini alongside."], "source": "hello_fresh_8.pdf"}, {"id": 63, "title": "CHICKEN FILLETS IN CRISPY HERB BREADING", "subtitle": "with fettuccine and spicy pumpkin seed pesto", "title_de": "HÄHNCHENFILETS IN KNUSPRIGER KRÄUTERPANADE", "prep_time_min": 40, "difficulty": 2, "protein_type": "chicken", "ingredients": [{"name_de": "Hähnchenbrustilets", "name": "chicken breasts", "quantity": "250", "unit": "g", "category": "meat & fish"}, {"name_de": "Knoblauchzehe", "name": "garlic clove", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Basilikum", "name": "basil", "quantity": "20", "unit": "g", "category": "produce"}, {"name_de": "Stangensellerie", "name": "celery", "quantity": "1", "unit": "Stück", "category": "produce"}, {"name_de": "Fettuccine", "name": "fettuccine", "quantity": "250", "unit": "g", "category": "pantry"}, {"name_de": "Kürbiskerne", "name": "pumpkin seeds", "quantity": "40", "unit": "g", "category": "pantry"}, {"name_de": "Semmelbrösel", "name": "breadcrumbs", "quantity": "38", "unit": "g", "category": "pantry"}, {"name_de": "Oregano", "name": "oregano", "quantity": "1", "unit": "Stück", "category": "pantry"}, {"name_de": "geriebener Hartkäse", "name": "grated hard cheese (parmesan-style)", "quantity": "25", "unit": "g", "category": "dairy & eggs"}], "steps": ["Fill a large pot with plenty of hot water, salt it, and bring to a boil. Slice the celery into approx. 0.5 cm thin rounds. Finely chop the garlic.", "Add the fettuccine to the boiling water along with the celery slices and cook together. At the end of the cooking time, drain everything through a sieve, reserving some pasta cooking water.", "In a tall mixing bowl, blend the pumpkin seeds, basil leaves, garlic, hard cheese, olive oil, 40 ml cold water, and 1 tbsp of the spice blend until a smooth pesto forms.", "Season the chicken breast fillets with salt and pepper. Cut each into 3 strips and press into the oregano-breadcrumb mixture to coat on both sides.", "Heat 1 tbsp oil in a large pan. Fry the breaded chicken strips for 3-4 min per side over medium heat until golden and cooked through.", "Toss the fettuccine with the pesto in the pot, adding a splash of pasta cooking water if needed. Divide into deep bowls and arrange the fried chicken fillets alongside. Enjoy."], "source": "hello_fresh_8.pdf"}];